import { useRef, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, Float } from '@react-three/drei';
import * as THREE from 'three';

const GlobeModel = () => {
  const globeRef = useRef<THREE.Group>(null);
  const dotsRef = useRef<THREE.Points>(null);

  // Create a spherical distribution of points for a "dot" globe effect
  const points = useMemo(() => {
    const positions = [];
    const count = 2000;
    const radius = 2;

    for (let i = 0; i < count; i++) {
      const phi = Math.acos(-1 + (2 * i) / count);
      const theta = Math.sqrt(count * Math.PI) * phi;

      const x = radius * Math.cos(theta) * Math.sin(phi);
      const y = radius * Math.sin(theta) * Math.sin(phi);
      const z = radius * Math.cos(phi);

      positions.push(x, y, z);
    }
    return new Float32Array(positions);
  }, []);

  // Destination markers (randomly placed for demo)
  const markers = useMemo(() => {
    const markerPositions = [];
    const count = 8;
    const radius = 2.05; // Slightly above surface

    for (let i = 0; i < count; i++) {
      const phi = Math.random() * Math.PI;
      const theta = Math.random() * 2 * Math.PI;

      const x = radius * Math.cos(theta) * Math.sin(phi);
      const y = radius * Math.sin(theta) * Math.sin(phi);
      const z = radius * Math.cos(phi);

      markerPositions.push(new THREE.Vector3(x, y, z));
    }
    return markerPositions;
  }, []);

  useFrame(() => {
    if (globeRef.current) {
      globeRef.current.rotation.y += 0.002;
    }
  });

  return (
    <group ref={globeRef}>
      {/* Main Globe Sphere (Subtle base) */}
      <mesh>
        <sphereGeometry args={[2, 64, 64]} />
        <meshPhongMaterial color="#f8fafc" transparent opacity={0.4} emissive="#e2e8f0" />
      </mesh>

      {/* Dot Pattern Overlay */}
      <points ref={dotsRef}>
        <bufferGeometry>
          <bufferAttribute
            attach="attributes-position"
            count={points.length / 3}
            array={points}
            itemSize={3}
            args={[points, 3]}
          />
        </bufferGeometry>
        <pointsMaterial size={0.03} color="#4f46e5" transparent opacity={0.3} sizeAttenuation />
      </points>

      {/* Destination Markers */}
      {markers.map((pos, i) => (
        <Float speed={2} rotationIntensity={0.5} floatIntensity={0.5} key={i}>
          <mesh position={pos}>
            <sphereGeometry args={[0.05, 16, 16]} />
            <meshBasicMaterial color="#ef4444" />
            <pointLight intensity={0.5} distance={1} color="#ef4444" />
          </mesh>
        </Float>
      ))}

      {/* Subtle atmosphere glow */}
      <mesh scale={1.05}>
        <sphereGeometry args={[2, 32, 32]} />
        <meshBasicMaterial color="#4f46e5" wireframe transparent opacity={0.05} />
      </mesh>
    </group>
  );
};

const Globe = () => {
  return (
    <div className="w-full h-[500px] cursor-grab active:cursor-grabbing">
      <Canvas>
        <PerspectiveCamera makeDefault position={[0, 0, 6]} />
        <ambientLight intensity={0.8} />
        <pointLight position={[10, 10, 10]} intensity={1.5} />
        <GlobeModel />
        <OrbitControls
          enableZoom={false}
          autoRotate
          autoRotateSpeed={0.5}
          enablePan={false}
          minPolarAngle={Math.PI / 4}
          maxPolarAngle={Math.PI / 1.5}
        />
      </Canvas>
    </div>
  );
};

export default Globe;

// src/components/home/Navbar.tsx
import { useEffect, useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { authService } from '../../services/c.authService';
import api from '../../utils/api';
import { User, ArrowLeft, MessageCircle, Loader2 } from 'lucide-react';
import { useSocketContext } from '../../context/SocketContext';
import { tripService } from '../../services/c.trip.service';
import type { ITrip } from '../../interface/ITripdetails';
import { TripStatus } from '../../constants/TripStatus';


interface NavbarProps {
  variant?: 'floating' | 'sticky';
  showBack?: boolean;
  backPath?: string;
}

export const Navbar = ({ variant = 'floating', showBack = false, backPath = '/' }: NavbarProps) => {
  const navigate = useNavigate();
  const user = authService.getCurrentUser();
  const { totalUnread, unreadCounts } = useSocketContext();
  const [kycStatus, setKycStatus] = useState<string>('loading');
  const [showChatDropdown, setShowChatDropdown] = useState(false);
  const [chatTrips, setChatTrips] = useState<ITrip[]>([]);
  const [loadingChats, setLoadingChats] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    let isMounted = true;
    const checkStatus = async () => {
      const userId = user?.id;
      if (userId) {
        try {
          const res = await api.get(`/api/kyc-status/${userId}`);
          if (isMounted) {
            setKycStatus(res.data.data?.status || 'none');
          }
        } catch (err) {
          if (isMounted) setKycStatus('none');
        }
      } else {
        if (isMounted) setKycStatus('loading');
      }
    };
    checkStatus();
    return () => {
      isMounted = false;
    };
  }, [user?.id]);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setShowChatDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleOpenChatDropdown = async () => {
    if (!user) {
      navigate('/login');
      return;
    }
    setShowChatDropdown(prev => !prev);
    if (chatTrips.length === 0) {
      try {
        setLoadingChats(true);
        const data = await tripService.getUserTrips(user.id, 1, 20);
        // Show trips that have a group chat (any status except cancelled)
        const activeTrips = data.trips.filter(t => t.status !== TripStatus.CANCELLED);
        setChatTrips(activeTrips);
      } catch {
        setChatTrips([]);
      } finally {
        setLoadingChats(false);
      }
    }
  };

  const handleLogout = () => {
    authService.logout();
    navigate('/');
  };

  const isFloating = variant === 'floating';

  return (
    <div
      className={`${isFloating ? 'fixed top-4 lg:top-6 left-1/2 -translate-x-1/2 w-[95%] max-w-7xl' : 'sticky top-0 w-full bg-white border-b border-slate-100'} z-[100] transition-all duration-300`}
    >
      <nav
        className={`flex justify-between items-center ${isFloating ? 'px-4 md:px-8 py-3 md:py-4 bg-white/70 backdrop-blur-xl border border-white/40 shadow-[0_8px_32px_rgba(0,0,0,0.05)] rounded-2xl md:rounded-[2rem]' : 'px-4 md:px-6 py-3'}`}
      >
        <div className="flex items-center gap-2 md:gap-4">
          {showBack && (
            <button
              onClick={() => navigate(backPath)}
              className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500"
            >
              <ArrowLeft size={18} />
            </button>
          )}
          <div
            className="font-black text-xl md:text-2xl cursor-pointer text-indigo-600 tracking-tighter"
            onClick={() => navigate('/')}
          >
            TripBuddy
          </div>
        </div>

        <div className="flex gap-2 md:gap-4 items-center">
          {user ? (
            <div className="flex items-center gap-2 md:gap-4">
              {kycStatus !== 'loading' && (
                <div className="hidden sm:block">
                  {kycStatus === 'none' ? (
                    <button
                      onClick={() => navigate('/kyc-verification')}
                      className="flex items-center gap-2 px-3 py-1.5 bg-amber-50 text-amber-700 border border-amber-200 rounded-full text-[10px] md:text-xs font-semibold hover:bg-amber-100 transition shadow-sm whitespace-nowrap"
                    >
                      <span className="relative flex h-2 w-2">
                        <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75"></span>
                        <span className="relative inline-flex rounded-full h-2 w-2 bg-amber-500"></span>
                      </span>
                      KYC
                    </button>
                  ) : (
                    <div
                      onClick={() => navigate('/kyc-status')}
                      className={`cursor-pointer flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] md:text-xs font-bold border shadow-sm transition-all hover:scale-105 whitespace-nowrap ${
                        kycStatus === 'approved'
                          ? 'bg-green-50 text-green-700 border-green-200'
                          : kycStatus === 'rejected'
                            ? 'bg-red-50 text-red-700 border-red-200'
                            : 'bg-blue-50 text-blue-700 border-blue-200'
                      }`}
                    >
                      {kycStatus === 'approved' && <span>✅ Verified</span>}
                      {kycStatus === 'pending' && <span>⏳ Pending</span>}
                      {kycStatus === 'rejected' && <span>❌ Rejected</span>}
                    </div>
                  )}
                </div>
              )}

              {/* Chat Icon with Dropdown */}
              <div className="relative" ref={dropdownRef}>
                <div
                  onClick={handleOpenChatDropdown}
                  className="relative cursor-pointer hover:bg-slate-50 p-2 rounded-xl transition-all group"
                >
                  <MessageCircle
                    size={20}
                    className={`transition-colors ${showChatDropdown ? 'text-indigo-600' : 'text-slate-400 group-hover:text-indigo-600'}`}
                  />
                  {totalUnread > 0 && (
                    <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[9px] font-black w-4 h-4 flex items-center justify-center rounded-full animate-bounce">
                      {totalUnread}
                    </span>
                  )}
                </div>

                {/* Dropdown */}
                {showChatDropdown && (
                  <div className="absolute right-0 top-full mt-2 w-72 bg-white rounded-2xl shadow-2xl border border-slate-100 overflow-hidden animate-in fade-in zoom-in-95 duration-150 z-50">
                    <div className="px-4 py-3 border-b border-slate-50 flex items-center justify-between">
                      <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                        Group Chats
                      </p>
                      <button
                        onClick={() => navigate('/profile')}
                        className="text-[10px] font-bold text-indigo-500 hover:text-indigo-700"
                      >
                        View Profile
                      </button>
                    </div>
                    <div className="max-h-64 overflow-y-auto">
                      {loadingChats ? (
                        <div className="flex items-center justify-center py-8">
                          <Loader2 size={20} className="animate-spin text-indigo-400" />
                        </div>
                      ) : chatTrips.length > 0 ? (
                        chatTrips.map(trip => {
                          const unread = unreadCounts[trip._id] || 0;
                          return (
                            <div
                              key={trip._id}
                              onClick={() => {
                                navigate(`/group-chat/${trip._id}`);
                                setShowChatDropdown(false);
                              }}
                              className="flex items-center gap-3 px-4 py-3 hover:bg-slate-50 cursor-pointer transition-colors group border-b border-slate-50/80"
                            >
                              <div className="w-8 h-8 bg-indigo-600 rounded-xl flex items-center justify-center text-white text-xs font-black shrink-0">
                                {trip.destination.charAt(0).toUpperCase()}
                              </div>
                              <div className="flex-1 min-w-0">
                                <p className="text-sm font-bold text-slate-800 truncate">
                                  {trip.title || trip.destination}
                                </p>
                                <p className="text-[10px] text-slate-400 font-medium capitalize">
                                  {trip.status}
                                </p>
                              </div>
                              {unread > 0 && (
                                <span className="bg-red-500 text-white text-[9px] font-black min-w-[18px] h-[18px] flex items-center justify-center rounded-full px-1">
                                  {unread}
                                </span>
                              )}
                            </div>
                          );
                        })
                      ) : (
                        <div className="py-8 text-center">
                          <p className="text-[10px] font-black uppercase tracking-widest text-slate-300">
                            No active trips
                          </p>
                          <button
                            onClick={() => {
                              navigate('/create-trip');
                              setShowChatDropdown(false);
                            }}
                            className="mt-2 text-xs text-indigo-500 font-bold hover:text-indigo-700"
                          >
                            Create a trip →
                          </button>
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </div>

              <div
                onClick={() => navigate('/profile')}
                className="flex items-center gap-2 cursor-pointer hover:bg-gray-50 p-1 md:px-3 md:py-2 rounded-xl transition group"
              >
                <div className="w-8 h-8 rounded-lg bg-indigo-50 flex items-center justify-center text-indigo-600 group-hover:bg-indigo-100 transition overflow-hidden border border-indigo-100">
                  {user.avatarURL ? (
                    <img src={user.avatarURL} alt="" className="w-full h-full object-cover" />
                  ) : (
                    <User className="w-4 h-4" />
                  )}
                </div>
                <span className="hidden md:block text-gray-600 text-sm font-medium">
                  Hi, <span className="text-indigo-600 font-bold">{user.name.split(' ')[0]}</span>
                </span>
              </div>

              <button
                onClick={handleLogout}
                className="text-xs md:text-sm font-bold text-slate-400 hover:text-red-500 transition-colors px-2 py-1"
              >
                Logout
              </button>
            </div>
          ) : (
            <div className="flex gap-2 lg:gap-4">
              <button
                onClick={() => navigate('/login')}
                className="text-gray-600 text-sm md:text-base font-medium px-2"
              >
                Login
              </button>
              <button
                onClick={() => navigate('/register')}
                className="px-4 md:px-6 py-2 bg-indigo-600 text-white rounded-xl text-sm md:text-base font-medium shadow-lg shadow-indigo-100"
              >
                Sign Up
              </button>
            </div>
          )}
        </div>
      </nav>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { MessageCircle, Plane, ArrowRight, Loader2 } from 'lucide-react';
import { tripService } from '../../services/c.trip.service';
import { Pagination } from '../Pagination';
import type { ITrip } from '../../interface/ITripdetails';
import { useSocketContext } from '../../context/SocketContext';

interface LiveChatsProps {
  userId: string;
}

export const LiveChats: React.FC<LiveChatsProps> = ({ userId }) => {
  const navigate = useNavigate();
  const { unreadCounts } = useSocketContext();
  const [trips, setTrips] = useState<ITrip[]>([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const LIMIT = 4;
  const [paginationLoading, setPaginationLoading] = useState(false);

  const fetchChats = async (pageNum: number = 1) => {
    if (!userId) return;
    try {
      if (pageNum === 1 && !paginationLoading) setLoading(true);
      else setPaginationLoading(true);

      const data = await tripService.getUserTrips(userId, pageNum, LIMIT);
      setTrips(data.trips);
      setTotal(data.total);
    } catch (error) {
      console.error('Error fetching chats:', error);
    } finally {
      setLoading(false);
      setPaginationLoading(false);
    }
  };

  useEffect(() => {
    if (userId) {
      fetchChats(page);
    }
  }, [userId, page]);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 bg-slate-50/50 rounded-2xl border border-dashed border-slate-200">
        <Loader2 className="w-8 h-8 text-indigo-500 animate-spin mb-4" />
        <p className="text-slate-500 font-medium">Loading your conversations...</p>
      </div>
    );
  }

  if (trips.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 bg-slate-50/50 rounded-2xl border border-dashed border-slate-200">
        <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mb-6 shadow-sm">
          <MessageCircle className="w-8 h-8 text-slate-300" />
        </div>
        <h3 className="text-lg font-bold text-slate-800 mb-2">No Active Chats</h3>
        <p className="text-slate-500 text-sm max-w-xs text-center">
          Join a trip or create one to start chatting with your travel buddies!
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="relative">
        {paginationLoading && (
          <div className="absolute inset-0 bg-white/60 backdrop-blur-[1px] z-10 flex items-center justify-center rounded-2xl animate-in fade-in duration-200">
            <Loader2 className="animate-spin text-indigo-500" size={32} />
          </div>
        )}
        <div
          className={`grid grid-cols-1 md:grid-cols-2 gap-4 transition-opacity duration-200 ${paginationLoading ? 'opacity-40' : 'opacity-100'}`}
        >
          {trips.map(trip => {
            const unreadCount = unreadCounts[trip._id] || 0;
            return (
              <div
                key={trip._id}
                className="group bg-white p-6 rounded-2xl border border-slate-100 hover:border-indigo-200 hover:shadow-md transition-all cursor-pointer flex items-center justify-between relative"
                onClick={() => navigate(`/group-chat/${trip._id}`)}
              >
                <div className="flex items-center gap-4">
                  <div className="relative">
                    <div className="bg-indigo-50 p-3 rounded-xl text-indigo-600 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                      <Plane size={24} />
                    </div>
                    {unreadCount > 0 && (
                      <div className="absolute -top-2 -right-2 bg-red-500 text-white text-[10px] font-black w-5 h-5 rounded-full flex items-center justify-center border-2 border-white animate-bounce">
                        {unreadCount > 9 ? '9+' : unreadCount}
                      </div>
                    )}
                  </div>
                  <div>
                    <h4 className="font-bold text-slate-800">{trip.title || trip.destination}</h4>
                    <p className="text-xs text-slate-500 font-medium">
                      {new Date(trip.startDate).toLocaleDateString(undefined, {
                        month: 'short',
                        day: 'numeric',
                      })}{' '}
                      -
                      {new Date(trip.endDate).toLocaleDateString(undefined, {
                        month: 'short',
                        day: 'numeric',
                      })}
                    </p>
                  </div>
                </div>
                <div className="flex flex-col items-end gap-2">
                  <span className="bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest">
                    {trip.members?.length || 0} Members
                  </span>
                  <div className="text-indigo-600 font-bold text-xs flex items-center gap-1 opacity-100 md:opacity-0 group-hover:opacity-100 transition-opacity">
                    Open Chat <ArrowRight size={14} />
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
      <Pagination
        currentPage={page}
        totalPages={Math.ceil(total / LIMIT)}
        onPageChange={p => setPage(p)}
      />
    </div>
  );
};

