  tripId: {
    _id: string;
    title: string;
    destination: string;
  };
  amount: number;
  status: string;
  paymentType: string;
  transactionId?: string;
  refundReason?: string;
  createdAt: string;
}

export const AdminPaymentsPage = () => {
  const [payments, setPayments] = useState<PaymentData[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedPayment, setSelectedPayment] = useState<{ id: string; status: string } | null>(
    null
  );
  const limit = 3;

  useEffect(() => {
    fetchPayments();
  }, [currentPage, searchTerm]);

  const fetchPayments = async () => {
    try {
      setLoading(true);
      const { data } = await api.get('/api/admin/payments', {
        params: { page: currentPage, limit, search: searchTerm },
      });
      setPayments(data.data.payments);
      // Calculating totalPages based on backend response (assuming backend doesn't provide it yet)
      setTotalPages(Math.ceil(data.data.total / limit));
    } catch (error) {
      toast.error('Failed to load payments');
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateStatus = async () => {
    if (!selectedPayment) return;
    try {
      await api.patch(`/api/admin/payments/${selectedPayment.id}/status`, {
        status: selectedPayment.status,
      });
      toast.success(`Payment status updated to ${selectedPayment.status}`);
      setPayments(
        payments.map(p =>
          p._id === selectedPayment.id ? { ...p, status: selectedPayment.status } : p
        )
      );
    } catch (error) {
      toast.error('Failed to update status');
    } finally {
      setIsModalOpen(false);
      setSelectedPayment(null);
    }
  };

  const columns = [
    {
      header: 'User',
      key: 'userId',
      render: (payment: PaymentData) => (
        <div className="flex items-center gap-3 max-w-[200px]">
          {payment.userId?.avatarURL ? (
            <img
              src={
                payment.userId.avatarURL.startsWith('http')
                  ? payment.userId.avatarURL
                  : `${api.defaults.baseURL}/${payment.userId.avatarURL}`
              }
              alt={payment.userId.name}
              className="w-8 h-8 rounded-full object-cover shrink-0"
            />
          ) : (
            <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center text-gray-500 text-xs font-bold shrink-0">
              {payment.userId?.name?.charAt(0) || 'U'}
            </div>
          )}
          <div className="truncate">
            <div className="font-medium text-gray-800 text-sm truncate">
              {payment.userId?.name || 'Unknown'}
            </div>
            <div className="text-xs text-gray-500 truncate">{payment.userId?.email || 'N/A'}</div>
          </div>
        </div>
      ),
    },
    {
      header: 'Trip',
      key: 'tripId',
      render: (payment: PaymentData) => (
        <div className="max-w-[180px]">
          <div className="font-medium text-gray-800 text-sm break-words line-clamp-2">
            {payment.tripId?.title || 'Unknown Trip'}
          </div>
          <div className="text-xs text-gray-400 truncate">
            {payment.tripId?.destination || 'N/A'}
