              className="p-1.5 bg-red-50 text-red-600 rounded-lg hover:bg-red-100 transition"
              title="Mark as Failed"
            >
              <XCircle size={16} />
            </button>
          )}
        </div>
      ),
    },
  ];

  return (
    <AdminLayout>
      <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
