import { useState, useEffect } from 'react';
import { Map, Search, XCircle, CheckCircle, Clock, Star, MessageSquare } from 'lucide-react';
import toast from 'react-hot-toast';
import { AdminLayout } from '../../components/admin/AdminLayout';
import api from '../../utils/api';
import { TripStatus } from '../../constants/TripStatus';
import { DataTable } from '../../components/DataTable';
import { Pagination } from '../../components/Pagination';
import { ConfirmModal } from '../../components/ConfirmModal';

interface TripUser {
  _id: string;
  name: string;
  email: string;
  avatarURL?: string;
}

interface TripData {
  _id: string;
  userId: TripUser;
  title: string;
  destination: string;
  startDate: string;
  endDate: string;
  budget?: number;
  status: string;
  members: string[];
  minMembers: number;
  preferences?: {
    travelers: number;
    accommodation: string;
    transport: string;
  };
  createdAt: string;
  guideId?: {
    _id: string;
    userId: {
      name: string;
    };
  };
}

interface Review {
  _id: string;
  reviewerId: {
    name: string;
    avatarURL?: string;
  };
  rating: number;
  comment: string;
  target?: string;
  createdAt: string;
}

const STATUS_OPTIONS = Object.values(TripStatus);

const statusStyles: Record<string, string> = {
  [TripStatus.PLANNED]: 'bg-blue-100 text-blue-700',
  [TripStatus.ONGOING]: 'bg-amber-100 text-amber-700',
  [TripStatus.COMPLETED]: 'bg-emerald-100 text-emerald-700',
  [TripStatus.CANCELLED]: 'bg-red-100 text-red-700',
  [TripStatus.FINALIZED]: 'bg-purple-100 text-purple-700',
  [TripStatus.CONFIRMED]: 'bg-teal-100 text-teal-700',
};

export const AdminTripManagementPage = () => {
  const [trips, setTrips] = useState<TripData[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalTrips, setTotalTrips] = useState(0);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedAction, setSelectedAction] = useState<{
    tripId: string;
    status: string;
    title: string;
  } | null>(null);

  // Review Modal State
  const [isReviewModalOpen, setIsReviewModalOpen] = useState(false);
  const [selectedTripReviews, setSelectedTripReviews] = useState<Review[]>([]);
  const [isReviewsLoading, setIsReviewsLoading] = useState(false);
  const [activeTripTitle, setActiveTripTitle] = useState('');

  const limit = 8;

  useEffect(() => {
    fetchTrips();
  }, [currentPage, searchTerm]);

  const fetchTrips = async () => {
    try {
      setLoading(true);
      const { data } = await api.get('/api/admin/trips', {
        params: { page: currentPage, limit, search: searchTerm },
      });
      setTrips(data.data.trips);
      setTotalPages(data.data.totalPages);
      setTotalTrips(data.data.totalTrips);
    } catch (err) {
      toast.error('Failed to load trips');
    } finally {
      setLoading(false);
    }
  };

  const confirmStatusUpdate = (trip: TripData, status: string) => {
    setSelectedAction({ tripId: trip._id, status, title: trip.title });
    setIsModalOpen(true);
  };

  const handleStatusUpdate = async () => {
    if (!selectedAction) return;
    try {
      await api.patch(`/api/admin/trips/${selectedAction.tripId}/status`, {
        status: selectedAction.status,
      });
      toast.success(`Trip status updated to "${selectedAction.status}"`);
      setTrips(prev =>
        prev.map(t =>
          t._id === selectedAction.tripId ? { ...t, status: selectedAction.status } : t
        )
      );
    } catch (err) {
      toast.error('Failed to update trip status');
    } finally {
      setIsModalOpen(false);
      setSelectedAction(null);
    }
  };

  const openReviews = async (trip: TripData) => {
    setActiveTripTitle(trip.title);
    setIsReviewModalOpen(true);
    setIsReviewsLoading(true);
    try {
      const { data } = await api.get(`/api/reviews/trip/${trip._id}`);
      setSelectedTripReviews(data.data);
    } catch (err) {
      toast.error('Failed to load reviews');
      setIsReviewModalOpen(false);
    } finally {
      setIsReviewsLoading(false);
    }
  };

  const columns = [
    {
      header: 'Trip',
      key: 'title',
      render: (trip: TripData) => (
        <div className="max-w-[200px]">
          <div className="font-semibold text-gray-800 text-sm truncate">{trip.title}</div>
          <div className="text-xs text-gray-500 truncate">📍 {trip.destination}</div>
        </div>
      ),
    },
    {
      header: 'Organizer',
      key: 'userId',
      render: (trip: TripData) => (
        <div className="flex items-center gap-2 max-w-[180px]">
          {trip.userId?.avatarURL ? (
            <img
              src={
                trip.userId.avatarURL.startsWith('http')
                  ? trip.userId.avatarURL
                  : `${api.defaults.baseURL}/${trip.userId.avatarURL}`
              }
              alt={trip.userId.name}
              className="w-8 h-8 rounded-full object-cover shrink-0"
            />
          ) : (
            <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 text-xs font-bold shrink-0">
              {trip.userId?.name?.charAt(0) || 'U'}
            </div>
          )}
          <div className="truncate">
            <div className="text-sm font-medium text-gray-800 truncate">
              {trip.userId?.name || 'Unknown'}
            </div>
            <div className="text-xs text-gray-500 truncate">{trip.userId?.email || 'N/A'}</div>
          </div>
        </div>
      ),
    },
    {
      header: 'Dates',
      key: 'startDate',
      className: 'hidden md:table-cell',
      render: (trip: TripData) => (
        <div className="text-xs text-gray-600">
          <div>{new Date(trip.startDate).toLocaleDateString()}</div>
          <div className="text-gray-400">→ {new Date(trip.endDate).toLocaleDateString()}</div>
        </div>
      ),
    },
    {
      header: 'Members',
      key: 'members',
      className: 'text-center hidden sm:table-cell',
      render: (trip: TripData) => (
        <span className="text-sm font-medium text-gray-700">
          {trip.members?.length ?? 0} / {trip.minMembers}
        </span>
      ),
    },
    {
      header: 'Budget',
      key: 'budget',
      className: 'text-right hidden lg:table-cell',
      render: (trip: TripData) => (
        <span className="text-sm font-bold text-gray-800">
          {trip.budget ? `₹${trip.budget.toLocaleString()}` : '—'}
        </span>
      ),
    },
    {
      header: 'Status',
      key: 'status',
      className: 'text-center',
      render: (trip: TripData) => (
        <span
          className={`px-2 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${statusStyles[trip.status] || 'bg-gray-100 text-gray-700'}`}
        >
          {trip.status}
        </span>
      ),
    },
    {
      header: 'Actions',
      key: 'actions',
      className: 'text-right',
      render: (trip: TripData) => (
        <div className="flex justify-end gap-2">
          {trip.status === TripStatus.COMPLETED && (
            <button
              onClick={() => openReviews(trip)}
              className="p-1.5 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-100 transition"
              title="View Reviews"
            >
              <Star size={16} />
            </button>
          )}
          {trip.status !== TripStatus.CANCELLED && trip.status !== TripStatus.COMPLETED && (
            <button
              onClick={() => confirmStatusUpdate(trip, TripStatus.CANCELLED)}
              className="p-1.5 bg-red-50 text-red-500 rounded-lg hover:bg-red-100 transition"
              title="Cancel Trip"
            >
              <XCircle size={16} />
            </button>
          )}
          {trip.status === TripStatus.PLANNED && (
            <button
              onClick={() => confirmStatusUpdate(trip, TripStatus.CONFIRMED)}
              className="p-1.5 bg-teal-50 text-teal-600 rounded-lg hover:bg-teal-100 transition"
              title="Confirm Trip"
            >
              <CheckCircle size={16} />
            </button>
          )}
          {trip.status === TripStatus.CONFIRMED && (
            <button
              onClick={() => confirmStatusUpdate(trip, TripStatus.ONGOING)}
              className="p-1.5 bg-amber-50 text-amber-600 rounded-lg hover:bg-amber-100 transition"
              title="Mark as Ongoing"
            >
              <Clock size={16} />
            </button>
          )}
          {trip.status === TripStatus.ONGOING && (
            <button
              onClick={() => confirmStatusUpdate(trip, TripStatus.COMPLETED)}
              className="p-1.5 bg-emerald-50 text-emerald-600 rounded-lg hover:bg-emerald-100 transition"
              title="Mark as Completed"
            >
              <CheckCircle size={16} />
            </button>
          )}
        </div>
      ),
    },
  ];

  return (
    <AdminLayout>
      <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
        {/* Header */}
        <div className="p-6 border-b border-gray-100 flex flex-col sm:flex-row justify-between items-center gap-4">
          <div>
            <h2 className="text-xl font-bold text-gray-800">Trip Management</h2>
            <p className="text-sm text-gray-500">
              {totalTrips > 0
                ? `${totalTrips} total trips`
                : 'Monitor and manage all platform trips'}
            </p>
          </div>
          <div className="flex items-center gap-4 w-full sm:w-auto">
            <div className="relative flex-1 sm:w-64">
              <Search
                className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"
                size={18}
              />
              <input
                type="text"
                placeholder="Search by title or destination..."
                className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-[#5537ee] text-sm"
                onChange={e => {
                  setSearchTerm(e.target.value);
                  setCurrentPage(1);
                }}
              />
            </div>
            <div className="bg-[#f0f9ff] p-2.5 rounded-xl text-[#5537ee] hidden sm:block">
              <Map size={20} />
            </div>
          </div>
        </div>

        {/* Status Filter Badges */}
        <div className="px-6 py-3 border-b border-gray-50 flex flex-wrap gap-2">
          {STATUS_OPTIONS.map(s => (
            <span
              key={s}
              className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider cursor-default ${statusStyles[s] || 'bg-gray-100 text-gray-700'}`}
            >
              {s}
            </span>
          ))}
        </div>

        <DataTable
          columns={columns}
          data={trips}
          loading={loading}
          emptyMessage="No trips found."
        />

        <div className="p-4 border-t bg-gray-50/50">
          <Pagination
            currentPage={currentPage}
            totalPages={totalPages}
            onPageChange={page => setCurrentPage(page)}
          />
        </div>
      </div>

      <ConfirmModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onConfirm={handleStatusUpdate}
        title="Update Trip Status"
        message={`Are you sure you want to change "${selectedAction?.title}" status to "${selectedAction?.status}"?`}
        confirmText="Yes, Update"
        type={selectedAction?.status === TripStatus.CANCELLED ? 'danger' : 'info'}
      />

      {/* Reviews Modal */}
      {isReviewModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
              <div>
                <h3 className="text-xl font-black text-slate-800 tracking-tight">Trip Reviews</h3>
                <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">
                  {activeTripTitle}
                </p>
              </div>
              <button
                onClick={() => setIsReviewModalOpen(false)}
                className="p-2 hover:bg-white rounded-full transition-colors shadow-sm"
              >
                <XCircle size={24} className="text-slate-400" />
              </button>
            </div>

            <div className="p-6 max-h-[60vh] overflow-y-auto custom-scrollbar">
              {isReviewsLoading ? (
                <div className="flex flex-col items-center justify-center py-12">
                  <div className="w-10 h-10 border-4 border-indigo-600/20 border-t-indigo-600 rounded-full animate-spin mb-4" />
                  <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">
                    Loading Feedback...
                  </p>
                </div>
              ) : selectedTripReviews.length === 0 ? (
                <div className="text-center py-12 bg-slate-50 rounded-[2rem] border-2 border-dashed border-slate-200">
                  <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-sm">
                    <MessageSquare size={32} className="text-slate-200" />
                  </div>
                  <h4 className="text-lg font-black text-slate-800">No reviews yet</h4>
                  <p className="text-sm text-slate-400 font-medium">
                    This trip hasn't received any feedback from members.
                  </p>
                </div>
              ) : (
                <div className="space-y-4">
                  {selectedTripReviews.map(review => (
                    <div
                      key={review._id}
                      className="bg-slate-50 rounded-[2rem] p-5 border border-slate-200/50"
                    >
                      <div className="flex justify-between items-start mb-3">
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center font-bold text-indigo-600 shadow-sm border border-slate-100 uppercase overflow-hidden">
                            {review.reviewerId.avatarURL ? (
                              <img
                                src={review.reviewerId.avatarURL}
                                alt=""
                                className="w-full h-full object-cover"
                              />
                            ) : (
                              review.reviewerId.name.charAt(0)
                            )}
                          </div>
                          <div>
                            <div className="text-sm font-black text-slate-800">
                              {review.reviewerId.name}
                            </div>
                            <div className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">
                              {new Date(review.createdAt).toLocaleDateString(undefined, {
                                month: 'short',
                                day: 'numeric',
                                year: 'numeric',
                              })}
                            </div>
                          </div>
                        </div>
                        <div className="flex gap-0.5">
                          {[...Array(5)].map((_, i) => (
                            <Star
                              key={i}
                              size={14}
                              className={
                                i < review.rating
                                  ? 'text-amber-400 fill-amber-400'
                                  : 'text-slate-200 fill-slate-200'
                              }
                            />
                          ))}
                        </div>
                      </div>
                      <p className="text-sm text-slate-600 leading-relaxed font-medium bg-white/60 p-4 rounded-2xl border border-white/40 italic">
                        "{review.comment}"
                      </p>
                      {review.target && (
                        <div className="mt-3 flex items-center gap-2">
                          <span className="text-[9px] font-black uppercase tracking-widest px-2 py-0.5 bg-indigo-100 text-indigo-600 rounded-md">
                            Target: {review.target}
                          </span>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="p-6 bg-gray-50 border-t border-gray-100 flex justify-end">
              <button
                onClick={() => setIsReviewModalOpen(false)}
                className="px-6 py-2.5 bg-slate-800 text-white rounded-xl text-sm font-bold hover:bg-slate-900 transition shadow-lg"
              >
                Close View
              </button>
            </div>
          </div>
        </div>
      )}
    </AdminLayout>
  );
};

import { useState, useEffect } from 'react';
import toast from 'react-hot-toast';
import { AdminLayout } from '../../components/admin/AdminLayout';
import { CheckCircle, XCircle, Eye } from 'lucide-react';
import api from '../../utils/api';
import { DataTable } from '../../components/DataTable';
import { SearchBar } from '../../components/common/SearchBar';
import { Pagination } from '../../components/Pagination';
import { ConfirmModal } from '../../components/ConfirmModal';

interface IGuideApplication {
  id: string;
  user: {
    id: string;
    name: string;
    email: string;
    role: string;
  };
  bio: string;
  hourlyRate: number;
  serviceArea: string;
  specialties: string[];
  avatarURL?: string;
  certificateUrl?: string;
  yearsOfExperience: number;
  isVerified: boolean;
  status: string;
  createdAt: string;
}

export const GuideManagement = () => {
  const [guides, setGuides] = useState<IGuideApplication[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [debouncedTerm, setDebouncedTerm] = useState('');
  const [loading, setLoading] = useState(true);
  const [viewingGuide, setViewingGuide] = useState<IGuideApplication | null>(null);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const limit = 3;

  const [isConfirmOpen, setIsConfirmOpen] = useState(false);
  const [guideToReject, setGuideToReject] = useState<string | null>(null);

  // Debounce search term
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedTerm(searchTerm);
      setCurrentPage(1); // Reset to first page on new search
    }, 500);

    return () => clearTimeout(handler);
  }, [searchTerm]);

  useEffect(() => {
    loadGuides();
  }, [currentPage, debouncedTerm]);

  const loadGuides = async () => {
    try {
      setLoading(true);
      const { data } = await api.get('/api/admin/guides', {
        params: { page: currentPage, limit, search: debouncedTerm },
      });
      console.log('from g-management', data.guides);
      setGuides(data.data.guides);
      setTotalPages(data.data.totalPages);
    } catch (err) {
      toast.error('Failed to load applications');
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (id: string) => {
    try {
      await api.patch(`/api/admin/guides/${id}/verify`);
      toast.success('Guide approved!');
      loadGuides();
    } catch (err) {
      toast.error('Approval failed');
    }
  };

  // Triggered when clicking the X button
  const initiateReject = (id: string) => {
    setGuideToReject(id);
    setIsConfirmOpen(true);
  };

  // Triggered when Confirm button inside modal is clicked
  const handleConfirmReject = async () => {
    if (!guideToReject) return;
    try {
      await api.delete(`/api/admin/guides/${guideToReject}`);
      toast.success('Application rejected');
      loadGuides();
    } catch (err) {
      toast.error('Rejection failed');
    } finally {
      setIsConfirmOpen(false);
      setGuideToReject(null);
    }
  };

  const columns = [
    {
      header: 'No.',
      key: 'index',
      className: 'hidden md:table-cell',
      render: (_: IGuideApplication, index: number) => (
        <span className="text-xs font-mono text-gray-400">
          {(currentPage - 1) * limit + (index + 1)}
        </span>
      ),
    },
    {
      header: 'Applicant',
      key: 'userId',
      render: (guide: IGuideApplication) => (
        <div className="py-1 max-w-[150px] sm:max-w-[200px]">
          <div className="font-bold text-gray-900 truncate">{guide.user?.name || 'Unknown'}</div>
          <div className="text-xs text-gray-500 truncate">{guide.user?.email}</div>
          <div className="text-[11px] italic text-gray-400 line-clamp-2 mt-1" title={guide.bio}>
            "{guide.bio}"
          </div>
        </div>
      ),
    },
    {
      header: 'Exp & Area',
      key: 'yearsOfExperience',
      className: 'hidden sm:table-cell',
      render: (guide: IGuideApplication) => (
        <div className="max-w-[120px]">
          <div className="text-sm font-semibold">{guide.yearsOfExperience} years</div>
          <div className="text-xs text-gray-500 truncate">{guide.serviceArea}</div>
          <div className="text-xs font-bold text-emerald-600">₹{guide.hourlyRate}/hr</div>
        </div>
      ),
    },
    {
      header: 'Status',
      key: 'isVerified',
      render: (guide: IGuideApplication) => (
        <span
          className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-tighter border ${
            guide.isVerified
              ? 'bg-emerald-50 text-emerald-700 border-emerald-200'
              : 'bg-amber-50 text-amber-700 border-amber-200'
          }`}
        >
          {guide.isVerified ? 'Verified' : 'Pending'}
        </span>
      ),
    },
    {
      header: 'Details',
      key: 'details',
      className: 'hidden lg:table-cell',
      render: (guide: IGuideApplication) => (
        <button
          onClick={() => setViewingGuide(guide)}
          className="flex items-center gap-1.5 text-[11px] font-bold text-[#5537ee] hover:text-white hover:bg-[#5537ee] bg-indigo-50/50 px-3 py-1.5 rounded-full border border-indigo-100 transition-all active:scale-95 group"
        >
          <Eye size={14} className="group-hover:scale-110 transition-transform" /> View
        </button>
      ),
    },
    {
      header: 'Actions',
      key: 'actions',
      className: 'text-right',
      render: (guide: IGuideApplication) => (
        <div className="flex justify-end gap-1">
          {!guide.isVerified && (
            <button
              onClick={() => handleApprove(guide.id)}
              className="p-1.5 text-green-600 hover:bg-green-100 rounded-lg transition"
              title="Verify Application"
            >
              <CheckCircle size={18} />
            </button>
          )}
          <button
            onClick={() => initiateReject(guide.id)}
            className="p-1.5 text-red-600 hover:bg-red-100 rounded-lg transition"
            title="Reject/Remove"
          >
            <XCircle size={18} />
          </button>
        </div>
      ),
    },
  ];

  return (
    <AdminLayout>
      <div className="p-6">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
          <div>
            <h2 className="text-2xl font-bold text-gray-800">Guide Directory</h2>
            <p className="text-sm text-gray-500">Manage and verify guide applications</p>
          </div>
          <SearchBar
            placeholder="Search by name, email or area..."
            onSearch={val => {
              setSearchTerm(val);
              setCurrentPage(1);
            }}
            className="max-w-xs"
          />
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <DataTable
            columns={columns}
            data={guides}
            loading={loading}
            emptyMessage="No guides found."
          />

          <div className="p-4 border-t bg-gray-50/30">
            <Pagination
              currentPage={currentPage}
              totalPages={totalPages}
              onPageChange={page => setCurrentPage(page)}
            />
          </div>
        </div>

        {/* Modal for PDF/Image certificates & Detailed Profile */}
        {viewingGuide && (
          <div className="fixed inset-0 bg-black/80 backdrop-blur-md flex items-center justify-center z-50 p-4 animate-in fade-in duration-300">
            <div className="bg-white rounded-2xl max-w-5xl w-full max-h-[90vh] flex flex-col shadow-2xl overflow-hidden animate-in zoom-in duration-300">
              {/* Header */}
              <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-white">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-indigo-50 flex items-center justify-center font-bold text-[#5537ee] border border-indigo-100 overflow-hidden">
                    {viewingGuide.avatarURL ? (
                      <img
                        src={viewingGuide.avatarURL}
                        alt=""
                        className="w-full h-full object-cover"
                      />
                    ) : (
                      viewingGuide.user?.name[0]
                    )}
                  </div>
                  <div>
                    <h3 className="font-bold text-gray-900 leading-tight">
                      {viewingGuide.user?.name}
                    </h3>
                    <p className="text-[10px] text-gray-500 uppercase tracking-widest font-bold">
                      Guide Application Review
                    </p>
                  </div>
                </div>
                <button
                  onClick={() => setViewingGuide(null)}
                  className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-all"
                >
                  <XCircle size={24} />
                </button>
              </div>

              <div className="flex flex-col md:flex-row flex-1 overflow-hidden min-h-125">
                {/* Image/Profile Side */}
                <div className="flex-1 bg-[#1e293b] p-6 flex flex-col items-center justify-center relative group overflow-y-auto">
                  {viewingGuide.avatarURL ? (
                    <div className="relative">
                      <img
                        src={viewingGuide.avatarURL}
                        alt="Profile"
                        className="max-w-full max-h-full rounded-2xl shadow-2xl transition-all duration-500 group-hover:scale-[1.01] border-4 border-white/10"
                      />
                      <div className="absolute top-4 left-4 bg-[#5537ee] text-white text-[10px] font-bold px-3 py-1 rounded-full shadow-lg">
                        PROFILE PHOTO
                      </div>
                    </div>
                  ) : (
                    <div className="text-gray-400 bg-gray-800/50 p-12 rounded-full flex flex-col items-center gap-4">
                      <span className="text-5xl font-bold">{viewingGuide.user?.name[0]}</span>
                      <p className="text-xs">No profile photo uploaded</p>
                    </div>
                  )}
                </div>

                {/* Info Side */}
                <div className="w-full md:w-112.5 p-8 bg-white border-l border-gray-100 flex flex-col justify-between overflow-y-auto">
                  <div className="space-y-8">
                    <div className="flex justify-between items-start">
                      <div>
                        <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                          Application Status
                        </label>
                        <div className="mt-2 text-sm font-bold flex items-center gap-2">
                          <span
                            className={`w-2.5 h-2.5 rounded-full ${viewingGuide.isVerified ? 'bg-emerald-500' : 'bg-amber-500'}`}
                          ></span>
                          <span className="uppercase tracking-tight text-gray-700">
                            {viewingGuide.status}
                          </span>
                        </div>
                      </div>
                      <div className="text-right">
                        <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                          Identification
                        </label>
                        {viewingGuide.certificateUrl ? (
                          <a
                            href={viewingGuide.certificateUrl}
                            target="_blank"
                            rel="noreferrer"
                            className="mt-2 flex items-center gap-1.5 text-[10px] font-bold text-[#5537ee] hover:underline"
                          >
                            <Eye size={12} /> View Certificate
                          </a>
                        ) : (
                          <p className="mt-2 text-[10px] text-red-400 font-bold">
                            Missing Document
                          </p>
                        )}
                      </div>
                    </div>

                    {/* Basic Details */}
                    <div className="grid grid-cols-2 gap-6 p-4 bg-gray-50 rounded-2xl border border-gray-100">
                      <div>
                        <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                          Experience
                        </label>
                        <p className="text-sm font-bold text-gray-800">
                          {viewingGuide.yearsOfExperience || 0} Years
                        </p>
                      </div>
                      <div>
                        <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                          Hourly Rate
                        </label>
                        <p className="text-sm font-bold text-emerald-600">
                          ₹{viewingGuide.hourlyRate || 0}/hr
                        </p>
                      </div>
                      <div className="col-span-2">
                        <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                          Service Area
                        </label>
                        <p className="text-sm font-semibold text-gray-700">
                          {viewingGuide.serviceArea || 'Not specified'}
                        </p>
                      </div>
                    </div>

                    {/* Bio */}
                    <div>
                      <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block mb-2">
                        Biography
                      </label>
                      <div className="p-4 bg-indigo-50/30 rounded-xl border border-indigo-100/50">
                        <p className="text-xs text-indigo-900 leading-relaxed italic">
                          "{viewingGuide.bio || 'No biography provided'}"
                        </p>
                      </div>
                    </div>

                    {/* Specialties */}
                    <div>
                      <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-3 block">
                        Specialties
                      </label>
                      <div className="flex flex-wrap gap-2">
                        {viewingGuide.specialties && viewingGuide.specialties.length > 0 ? (
                          viewingGuide.specialties.map((s, i) => (
                            <span
                              key={i}
                              className="px-3 py-1.5 bg-white text-indigo-700 text-[10px] font-bold rounded-lg border border-indigo-100 shadow-sm"
                            >
                              {s}
                            </span>
                          ))
                        ) : (
                          <span className="text-[10px] text-gray-400 italic">None specified</span>
                        )}
                      </div>
                    </div>
                  </div>

                  <div className="space-y-3 pt-8 border-t border-gray-100 mt-8">
                    {!viewingGuide.isVerified && (
                      <button
                        onClick={() => {
                          handleApprove(viewingGuide.id);
                          setViewingGuide(null);
                        }}
                        className="w-full bg-[#5537ee] hover:bg-[#4428d4] text-white py-4 rounded-xl font-bold text-xs transition-all shadow-xl shadow-indigo-100 active:scale-95 flex items-center justify-center gap-2"
                      >
                        <CheckCircle size={18} /> Approve Application
                      </button>
                    )}
                    <button
                      onClick={() => {
                        initiateReject(viewingGuide.id);
                        setViewingGuide(null);
                      }}
                      className="w-full bg-red-50 hover:bg-red-100 text-red-600 py-4 rounded-xl font-bold text-xs transition-all active:scale-95 flex items-center justify-center gap-2"
                    >
                      <XCircle size={18} /> Reject Application
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Reusable ConfirmModal for Rejection */}
        <ConfirmModal
          isOpen={isConfirmOpen}
          onClose={() => {
            setIsConfirmOpen(false);
            setGuideToReject(null);
          }}
          onConfirm={handleConfirmReject}
          title="Reject Application"
          message="Are you sure you want to reject this guide application? This will permanently delete their guide profile data."
          confirmText="Reject Application"
          type="danger"
        />
      </div>
    </AdminLayout>
  );
};

import { Star, Trash2, MapPin, User, Calendar, MessageSquare, AlertCircle } from 'lucide-react';
import api from '../../utils/api';
import toast from 'react-hot-toast';
import { ConfirmModal } from '../../components/ConfirmModal';

interface Review {
  _id: string;
  tripId: {
    _id: string;
    destination: string;
  };
  reviewerId: {
    _id: string;
    name: string;
    avatarURL?: string;
  };
  organizerId: {
    _id: string;
    name: string;
  };
  rating: number;
  comment: string;
  createdAt: string;
}

export const ReviewManagementPage: React.FC = () => {
  const [reviews, setReviews] = useState<Review[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [reviewToDeleteId, setReviewToDeleteId] = useState<string | null>(null);

  useEffect(() => {
    loadReviews();
  }, []);

  const loadReviews = async () => {
    try {
      const res = await api.get('/api/reviews/admin/all');
      setReviews(res.data.data);
    } catch (err) {
      toast.error('Failed to load reviews');
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!reviewToDeleteId) return;

    try {
      await api.delete(`/api/reviews/${reviewToDeleteId}`);
      toast.success('Review deleted');
      setReviews(prev => prev.filter(r => r._id !== reviewToDeleteId));
    } catch (err) {
      toast.error('Failed to delete review');
    } finally {
      setShowDeleteConfirm(false);
      setReviewToDeleteId(null);
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="w-12 h-12 border-4 border-indigo-600/30 border-t-indigo-600 rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 p-6 md:p-10">
      <div className="max-w-7xl mx-auto">
        <header className="mb-10 flex justify-between items-center">
          <div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight mb-2">
              Review Management
            </h1>
            <p className="text-slate-500 font-medium">
              Monitor and manage traveler feedback across the platform.
            </p>
          </div>
        </header>

        {reviews.length === 0 ? (
          <div className="bg-white rounded-3xl p-16 text-center border-2 border-dashed border-slate-200">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6">
              <MessageSquare size={40} className="text-slate-300" />
            </div>
            <h3 className="text-xl font-bold text-slate-800 mb-2">No reviews found</h3>
            <p className="text-slate-500">
              Reviews will appear here once travelers complete their trips.
            </p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {reviews.map(review => (
              <div
                key={review._id}
                className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex flex-col hover:shadow-xl hover:shadow-slate-200/50 transition-all duration-300 group"
              >
                <div className="flex items-start justify-between mb-4">
                  <div className="flex items-center gap-3">
                    <div className="w-12 h-12 bg-slate-100 rounded-2xl overflow-hidden shadow-inner">
                      {review.reviewerId.avatarURL ? (
                        <img
                          src={review.reviewerId.avatarURL}
                          alt={review.reviewerId.name}
                          className="w-full h-full object-cover"
                        />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center bg-indigo-50 text-indigo-600 font-bold">
                          {review.reviewerId.name.charAt(0)}
                        </div>
                      )}
                    </div>
                    <div>
                      <h4 className="font-bold text-slate-800 line-clamp-1">
                        {review.reviewerId.name}
                      </h4>
                      <div className="flex gap-0.5 mt-1">
                        {[...Array(5)].map((_, i) => (
                          <Star
                            key={i}
                            size={14}
                            className={
                              i < review.rating
                                ? 'text-amber-400 fill-amber-400'
                                : 'text-slate-200 fill-slate-200'
                            }
                          />
                        ))}
                      </div>
                    </div>
                  </div>
                  <button
                    onClick={() => {
                      setReviewToDeleteId(review._id);
                      setShowDeleteConfirm(true);
                    }}
                    className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>

                <ConfirmModal
                  isOpen={showDeleteConfirm}
                  onClose={() => setShowDeleteConfirm(false)}
                  onConfirm={handleDelete}
                  title="Delete Review?"
                  message="Are you sure you want to delete this review? This action cannot be undone and will be removed from the organizer's profile."
                  confirmText="Yes, Delete Review"
                  type="danger"
                />

                <div className="flex-1 bg-slate-50/50 rounded-2xl p-4 mb-4 border border-slate-50">
                  <p className="text-slate-600 text-sm leading-relaxed italic">
                    "{review.comment}"
                  </p>
                </div>

                <div className="space-y-2 pt-4 border-t border-slate-50">
                  <div className="flex items-center gap-2 text-xs font-bold text-slate-400 uppercase tracking-widest">
                    <MapPin size={12} className="text-indigo-400" />
                    <span>Trip to {review.tripId?.destination || 'Deleted Trip'}</span>
                  </div>
                  <div className="flex items-center gap-2 text-xs font-bold text-slate-400 uppercase tracking-widest">
                    <User size={12} className="text-indigo-400" />
                    <span>Organizer: {review.organizerId?.name || 'Unknown'}</span>
                  </div>
                  <div className="flex items-center gap-2 text-xs font-bold text-slate-400 uppercase tracking-widest">
                    <Calendar size={12} className="text-indigo-400" />
                    <span>{new Date(review.createdAt).toLocaleDateString()}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

import { useState, useEffect } from 'react';
import { Search, Ban, Trash2, UserCheck, Check, X, FileText } from 'lucide-react';
import toast from 'react-hot-toast';
import { AdminLayout } from '../../components/admin/AdminLayout';
import api from '../../utils/api';
import { DataTable } from '../../components/DataTable';
import { Pagination } from '../../components/Pagination';
import { ConfirmModal } from '../../components/ConfirmModal';
// import { DataTable } from '../../components/common/DataTable'; // Import the new component

interface UserData {
  id: string;
  name: string;
  email: string;
  role: 'admin' | 'guide' | 'user';
  isBlocked: boolean;
  kycStatus: 'none' | 'pending' | 'approved' | 'rejected';
  kycDocument?: string;
  kycRejectionReason?: string;
  avatarURL?: string;
}

export const UserManagement = () => {
  const [users, setUsers] = useState<UserData[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedUserId, setSelectedUserId] = useState<string | null>(null);
  const [isBlockModalOpen, setIsBlockModalOpen] = useState(false);
  const [userToBlock, setUserToBlock] = useState<UserData | null>(null);
  const [isKYCModalOpen, setIsKYCModalOpen] = useState(false);
  const [selectedKYCUser, setSelectedKYCUser] = useState<UserData | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');
  const limit = 3;

  useEffect(() => {
    fetchUsers();
  }, [currentPage, searchTerm]);

  const fetchUsers = async () => {
    try {
      setLoading(true);
      const { data } = await api.get('/api/admin/users', {
        params: { page: currentPage, limit, search: searchTerm },
      });
      console.log('data from usermanagement:', data.data.users);
      setUsers(data.data.users);
      setTotalPages(data.data.totalPages);
    } catch (error) {
      toast.error('Failed to load users');
    } finally {
      setLoading(false);
    }
  };

  const handleBlockClick = (user: UserData) => {
    setUserToBlock(user);
    setIsBlockModalOpen(true);
  };

  const confirmBlock = async () => {
    if (!userToBlock) return;
    try {
      const { id, isBlocked } = userToBlock;
      await api.patch(`/api/admin/users/${id}/block`, { blocked: !isBlocked });
      toast.success(isBlocked ? 'User unblocked' : 'User blocked');
      setUsers(users.map(u => (u.id === id ? { ...u, isBlocked: !isBlocked } : u)));
    } catch (error) {
      toast.error('Action failed');
    } finally {
      setIsBlockModalOpen(false);
      setUserToBlock(null);
    }
  };

  const handleVerifyKYC = async (userId: string, status: 'approved' | 'rejected') => {
    try {
      if (status === 'rejected' && !rejectionReason.trim()) {
        toast.error('Please provide a reason for rejection');
        return;
      }
      await api.patch(`/api/admin/kyc/${userId}/approve`, { status, reason: rejectionReason });
      toast.success(`KYC ${status === 'approved' ? 'Approved' : 'Rejected'}`);
      setUsers(users.map(u => (u.id === userId ? { ...u, kycStatus: status } : u)));
      setIsKYCModalOpen(false);
      setRejectionReason('');
    } catch (error) {
      toast.error('Failed to update KYC status');
    }
  };

  const handleDeleteClick = (userId: string) => {
    setSelectedUserId(userId);
    setIsModalOpen(true);
  };
  const confirmDelete = async () => {
    if (!selectedUserId) return;
    try {
      await api.delete(`/api/admin/users/${selectedUserId}`);
      toast.success('User deleted successfully');
      setUsers(users.filter(u => u.id !== selectedUserId));
    } catch (error) {
      toast.error('Deletion failed');
    } finally {
      setIsModalOpen(false);
      setSelectedUserId(null);
    }
  };

  const columns = [
    {
      header: 'User',
      key: 'name',
      render: (user: UserData) => (
        <div className="flex items-center gap-3">
          {user.avatarURL ? (
            <img
              src={
                user.avatarURL.startsWith('http')
                  ? user.avatarURL
                  : `${api.defaults.baseURL}/${user.avatarURL}`
              }
              alt={user.name}
              className="w-10 h-10 rounded-full object-cover"
            />
          ) : (
            <div className="w-10 h-10 rounded-full bg-[#f0f9ff] flex items-center justify-center text-[#5537ee] font-bold">
              {user.name.charAt(0)}
            </div>
          )}
          <div>
            <div className="font-semibold text-gray-800">{user.name}</div>
            <div className="text-xs text-gray-500">{user.email}</div>
          </div>
        </div>
      ),
    },
    {
      header: 'Role',
      key: 'role',
      render: (user: UserData) => (
        <span
          className={`px-3 py-1 rounded-full text-xs font-medium ${
            user.role === 'admin'
              ? 'bg-purple-100 text-purple-700'
              : user.role === 'guide'
                ? 'bg-blue-100 text-blue-700'
                : 'bg-gray-100 text-gray-700'
          }`}
        >
          {user.role}
        </span>
      ),
    },
    {
      header: 'Status',
      key: 'isBlocked',
      render: (user: UserData) => (
        <span
          className={`flex items-center gap-1 text-xs font-bold ${user.isBlocked ? 'text-red-500' : 'text-emerald-500'}`}
        >
          <span
            className={`w-2 h-2 rounded-full ${user.isBlocked ? 'bg-red-500' : 'bg-emerald-500'}`}
          ></span>
          {user.isBlocked ? 'Blocked' : 'Active'}
        </span>
      ),
    },
    {
      header: 'KYC Status',
      key: 'kycStatus',
      render: (user: UserData) => (
        <span
          className={`px-2 py-1 rounded-lg text-[10px] font-bold uppercase tracking-wider ${
            user.kycStatus === 'approved'
              ? 'bg-emerald-100 text-emerald-700'
              : user.kycStatus === 'pending'
                ? 'bg-amber-100 text-amber-700'
                : user.kycStatus === 'rejected'
                  ? 'bg-red-100 text-red-700'
                  : 'bg-gray-100 text-gray-700'
          }`}
        >
          {user.kycStatus || 'None'}
        </span>
      ),
    },
    {
      header: 'Documents',
      key: 'kycDocument',
      render: (user: UserData) =>
        user.kycStatus !== 'none' ? (
          <button
            onClick={() => {
              setSelectedKYCUser(user);
              setRejectionReason(user.kycRejectionReason || '');
              setIsKYCModalOpen(true);
            }}
            className="flex items-center gap-1.5 text-xs font-medium text-[#5537ee] hover:underline"
          >
            <FileText size={14} />
            View Document
          </button>
        ) : (
          <span className="text-xs text-gray-400 italic">Not Uploaded</span>
        ),
    },
    {
      header: 'Block/Unblock',
      key: 'actions',
      className: 'text-right',
      render: (user: UserData) => (
        <div className="flex justify-end gap-2">
          <button
            onClick={() => handleBlockClick(user)}
            className={`p-2 rounded-lg transition ${user.isBlocked ? 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100' : 'bg-red-50 text-red-600 hover:bg-red-100'}`}
            title={user.isBlocked ? 'Unblock' : 'Block'}
          >
            {user.isBlocked ? <UserCheck size={18} /> : <Ban size={18} />}
          </button>
        </div>
      ),
    },
    {
      header: 'Actions',
      key: 'actions',
      className: 'text-right',
      render: (user: UserData) => (
        <div className="flex justify-end gap-2">
          <button
            onClick={() => handleDeleteClick(user.id)}
            className="p-2 bg-gray-50 text-gray-600 rounded-lg hover:bg-red-50 hover:text-red-600 transition"
          >
            <Trash2 size={18} />
          </button>
        </div>
      ),
    },
  ];

  return (
    <AdminLayout>
      <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
        {/* Toolbar */}
        <div className="p-6 border-b border-gray-100 flex flex-col sm:flex-row justify-between items-center gap-4">
          <h2 className="text-xl font-bold text-gray-800">User Directory</h2>
          <div className="relative flex-1 sm:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input
              type="text"
              placeholder="Search users..."
              className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-[#5537ee]"
              onChange={e => {
                setSearchTerm(e.target.value);
                setCurrentPage(1);
              }}
            />
          </div>
        </div>

        {/* Reusable Data Table */}
        <DataTable
          columns={columns}
          data={users}
          loading={loading}
          emptyMessage="No users found."
        />

        {/* Footer with Pagination */}
        <div className="p-4 border-t">
          <Pagination
            currentPage={currentPage}
            totalPages={totalPages}
            onPageChange={page => setCurrentPage(page)}
          />
        </div>
      </div>
      <ConfirmModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onConfirm={confirmDelete}
        title="Delete User"
        message="Are you sure you want to delete this user? This action cannot be undone."
        confirmText="Yes, Delete"
      />

      <ConfirmModal
        isOpen={isBlockModalOpen}
        onClose={() => setIsBlockModalOpen(false)}
        onConfirm={confirmBlock}
        title={userToBlock?.isBlocked ? 'Unblock User' : 'Block User'}
        message={`Are you sure you want to ${userToBlock?.isBlocked ? 'unblock' : 'block'} ${userToBlock?.name}?`}
        confirmText={userToBlock?.isBlocked ? 'Yes, Unblock' : 'Yes, Block'}
        type={userToBlock?.isBlocked ? 'info' : 'warning'}
      />

      {/* KYC View Modal */}
      {isKYCModalOpen && selectedKYCUser && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div
            className="fixed inset-0 bg-black/60 backdrop-blur-sm"
            onClick={() => {
              setIsKYCModalOpen(false);
              setRejectionReason('');
            }}
          />
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl relative z-10 overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b flex justify-between items-center">
              <div>
                <h3 className="text-xl font-bold text-gray-900">KYC Verification</h3>
                <p className="text-sm text-gray-500">Review documents for {selectedKYCUser.name}</p>
              </div>
              <button
                onClick={() => {
                  setIsKYCModalOpen(false);
                  setRejectionReason('');
                }}
                className="p-2 hover:bg-gray-100 rounded-full transition-colors"
              >
                <X size={20} />
              </button>
            </div>

            <div className="p-6 max-h-[60vh] overflow-y-auto bg-gray-50 flex items-center justify-center">
              {selectedKYCUser.kycDocument ? (
                selectedKYCUser.kycDocument.startsWith('http') ? (
                  selectedKYCUser.kycDocument.endsWith('.pdf') ? (
                    <iframe
                      src={selectedKYCUser.kycDocument}
                      className="w-full h-125 border-0 rounded-lg shadow-sm"
                    />
                  ) : (
                    <img
                      src={selectedKYCUser.kycDocument}
                      alt="KYC Document"
                      className="max-w-full rounded-lg shadow-md"
                    />
                  )
                ) : selectedKYCUser.kycDocument.endsWith('.pdf') ? (
                  <iframe
                    src={`${api.defaults.baseURL}/${selectedKYCUser.kycDocument}`}
                    className="w-full h-125 border-0 rounded-lg shadow-sm"
                  />
                ) : (
                  <img
                    src={`${api.defaults.baseURL}/${selectedKYCUser.kycDocument}`}
                    alt="KYC Document"
                    className="max-w-full rounded-lg shadow-md"
                  />
                )
              ) : (
                <div className="py-20 text-center">
                  <FileText size={48} className="mx-auto text-gray-300 mb-4" />
                  <p className="text-gray-500">No document found.</p>
                </div>
              )}
            </div>

            <div className="p-6 bg-white border-t space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Status Reason / Notes (Required for rejection)
                </label>
                <textarea
                  value={rejectionReason}
                  onChange={e => setRejectionReason(e.target.value)}
                  placeholder="Provide a reason or internal note..."
                  className="w-full px-4 py-2 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-[#5537ee] min-h-20"
                />
              </div>
              <div className="flex gap-3">
                <button
                  onClick={() => handleVerifyKYC(selectedKYCUser.id, 'rejected')}
                  className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 border border-red-200 text-red-600 rounded-xl hover:bg-red-50 font-semibold transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <X size={18} />
                  Reject
