// frontend/src/modules/auth/pages/ForgotPasswordPage.tsx
import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { Button } from '../../components/Button';
import api from '../../utils/api';
import { authService } from '../../services/c.authService';

export const ForgotPasswordPage = () => {
  const [email, setEmail] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    if (authService.getCurrentUser()) {
      navigate('/', { replace: true });
    }
  }, [navigate]);

  const validateEmail = (email: string) => {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return re.test(email);
  };

  const handleResetRequest = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!email.trim()) {
      setError('Email is required');
      return;
    }
    if (!validateEmail(email)) {
      setError('Please enter a valid email address');
      return;
    }

    setIsLoading(true);
    const resetToast = toast.loading('Sending verification email...');

    try {
      await api.post('/api/users/forgot-password', { email });

      toast.success('Verification email sent! Check your inbox.', { id: resetToast });
      setTimeout(() => navigate('/login'), 3000);
    } catch (error: unknown) {
      const errorObj = error as { response?: { data?: { message?: string } } };
      const msg = errorObj.response?.data?.message || 'An unexpected error occurred.';
      toast.error(error.response?.data?.message || 'Failed to send email. Try again later.', {
        id: resetToast,
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4">
      <div className="max-w-md w-full bg-white p-8 rounded-2xl shadow-lg">
        <h2 className="text-2xl font-bold text-gray-900 text-center mb-2">Reset Password</h2>
        <p className="text-gray-500 text-center mb-8">
          Enter your email and we'll send you a verification link.
        </p>

        <form onSubmit={handleResetRequest} className="space-y-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Email Address</label>
            <input
              type="email"
              className={`w-full px-4 py-3 rounded-xl border ${
                error ? 'border-red-500' : 'border-gray-200'
              } focus:ring-2 focus:ring-[#5537ee] outline-none transition-all`}
              placeholder="name@example.com"
              value={email}
              onChange={e => {
                setEmail(e.target.value);
                if (error) setError('');
              }}
            />
            {error && <p className="mt-1 text-xs text-red-500 font-medium">{error}</p>}
          </div>
          <Button type="submit" className="w-full py-3" disabled={isLoading}>
            {isLoading ? 'Sending...' : 'Send Verification'}
          </Button>
          <div className="text-center">
            <button
              type="button"
              onClick={() => navigate('/login')}
              className="text-sm text-gray-500 hover:text-[#5537ee]"
            >
              Back to Login
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import api from '../../utils/api';
import { Button } from '../../components/Button';
import { authService } from '../../services/c.authService';

export const ResetPasswordPage = () => {
  const { token } = useParams();
  const navigate = useNavigate();

  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [errors, setErrors] = useState({ password: '', confirmPassword: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    if (authService.getCurrentUser()) {
      navigate('/', { replace: true });
    }
  }, [navigate]);

  const validateForm = () => {
    let isValid = true;
    const newErrors = { password: '', confirmPassword: '' };

    if (!password) {
      newErrors.password = 'Password is required';
      isValid = false;
    } else if (password.length < 6) {
      newErrors.password = 'Password must be at least 6 characters';
      isValid = false;
    }

    if (!confirmPassword) {
      newErrors.confirmPassword = 'Please confirm your password';
      isValid = false;
    } else if (password !== confirmPassword) {
      newErrors.confirmPassword = 'Passwords do not match';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateForm()) return;

    setIsSubmitting(true);
    const loadToast = toast.loading('Updating password...');

    try {
      await api.post(`/api/users/reset-password/${token}`, { password });

      toast.success('Password reset successful! Redirecting to login...', { id: loadToast });
      setTimeout(() => navigate('/login'), 3000);
    } catch (error: unknown) {
      const errorObj = error as { response?: { data?: { message?: string } } };
      const msg = errorObj.response?.data?.message || 'An unexpected error occurred.';
      toast.error(error.response?.data?.message || 'Link expired or invalid', { id: loadToast });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4">
      <div className="max-w-md w-full bg-white p-8 rounded-2xl shadow-lg">
        <h2 className="text-2xl font-bold text-center mb-6">Create New Password</h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">New Password</label>
            <input
              type="password"
              className={`w-full px-4 py-3 rounded-xl border ${
                errors.password ? 'border-red-500' : 'border-gray-200'
              } focus:ring-2 focus:ring-[#5537ee] outline-none transition-all`}
              value={password}
              onChange={e => {
                setPassword(e.target.value);
                if (errors.password) setErrors({ ...errors, password: '' });
              }}
            />
            {errors.password && (
              <p className="mt-1 text-xs text-red-500 font-medium">{errors.password}</p>
            )}
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Confirm New Password
            </label>
            <input
              type="password"
              className={`w-full px-4 py-3 rounded-xl border ${
                errors.confirmPassword ? 'border-red-500' : 'border-gray-200'
              } focus:ring-2 focus:ring-[#5537ee] outline-none transition-all`}
              value={confirmPassword}
              onChange={e => {
                setConfirmPassword(e.target.value);
                if (errors.confirmPassword) setErrors({ ...errors, confirmPassword: '' });
              }}
            />
            {errors.confirmPassword && (
              <p className="mt-1 text-xs text-red-500 font-medium">{errors.confirmPassword}</p>
            )}
          </div>
          <Button type="submit" className="w-full py-3" disabled={isSubmitting}>
            {isSubmitting ? 'Resetting...' : 'Update Password'}
          </Button>
        </form>
      </div>
    </div>
  );
};

import { useEffect, useRef } from 'react'; // 1. Import useRef
import { useSearchParams, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { authService } from '../../services/c.authService';

const VerifyEmail = () => {
  const [params] = useSearchParams();
  const navigate = useNavigate();
  // 2. Create a ref to track if verification has started
  const hasStarted = useRef(false);

  useEffect(() => {
    const token = params.get('token');

    if (!token) {
      toast.error('Invalid verification link');
      return;
    }

    // 3. Check the ref. If true, skip the rest of the function.
    if (hasStarted.current) return;

    // 4. Set it to true immediately
    hasStarted.current = true;

    const verify = async () => {
      try {
        await authService.verifyEmail(token);
        toast.success('Email verified successfully 🎉');
        navigate('/login');
      } catch (err: unknown) {
      const errorObj = err as { response?: { data?: { message?: string } } };
      const msg = errorObj.response?.data?.message || 'An unexpected error occurred.';
        // If the first one succeeded, the user is likely verified.
        // You might want to check if the error is "INVALID_TOKEN_OR_EXPIRED"
        // and ignore it if the user is already redirected.
        toast.error(err.response?.data?.message || 'Verification failed');
      }
    };

    verify();
