import toast from 'react-hot-toast';

const GalleryPage = () => {
  const { userId } = useParams<{ userId?: string }>();
  const navigate = useNavigate();
  const currentUser = authService.getCurrentUser();

  // Is this the current user's OWN gallery?
  const isOwnGallery = !userId || userId === currentUser?.id;

  const [posts, setPosts] = useState<GalleryPost[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadData, setUploadData] = useState({
    caption: '',
    tripName: '',
    image: '',
  });
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    fetchPosts();
  }, [userId]);

  const fetchPosts = async () => {
    try {
      setLoading(true);
      setError(null);

      let res;
      if (isOwnGallery) {
        // Fetch current user's gallery
        res = await galleryService.getUserPosts(currentUser?.id || '');
      } else {
        // Fetch target user's gallery
        res = await galleryService.getUserPosts(userId!);
      }
      setPosts(res.data);
    } catch (error: unknown) {
      const errorObj = error as { response?: { data?: { message?: string } } };
      const msg = errorObj.response?.data?.message || 'An unexpected error occurred.';
      const message = error.response?.data?.message || 'Failed to load gallery';
      setError(message);
      toast.error(message);
    } finally {
      setLoading(false);
    }
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      setIsUploading(true);
      const res = await galleryService.uploadImage(file);
      setUploadData(prev => ({ ...prev, image: res.data.imageUrl }));
      toast.success('Photo uploaded successfully');
    } catch (error) {
      toast.error('Upload failed');
    } finally {
      setIsUploading(false);
    }
  };

  const handlePostSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!uploadData.image) return toast.error('Please upload an image first');

    try {
      setIsUploading(true);
      await galleryService.createPost(uploadData);
      setShowUploadModal(false);
      setUploadData({ caption: '', tripName: '', image: '' });
      fetchPosts();
      toast.success('Memory posted to gallery!');
    } catch (error) {
      toast.error('Failed to post');
    } finally {
      setIsUploading(false);
    }
  };

  // Helper to format time relative to now without external library
  const formatRelativeTime = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffInSeconds = Math.floor((now.getTime() - date.getTime()) / 1000);

    if (diffInSeconds < 60) return 'Just now';
    if (diffInSeconds < 3600) return `${Math.floor(diffInSeconds / 60)}m ago`;
    if (diffInSeconds < 86400) return `${Math.floor(diffInSeconds / 3600)}h ago`;
    if (diffInSeconds < 604800) return `${Math.floor(diffInSeconds / 86400)}d ago`;

    return date.toLocaleDateString('en-US', { day: 'numeric', month: 'short' });
  };

  if (!currentUser) {
    navigate('/login');
    return null;
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] pb-20 font-outfit">
      {/* Header Area */}
      <div className="bg-white/80 backdrop-blur-md border-b border-slate-100 sticky top-0 z-30">
        <div className="max-w-5xl mx-auto px-6 py-4 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <button
              onClick={() => navigate(-1)}
              className="p-2 hover:bg-slate-50 rounded-full text-slate-400 hover:text-indigo-600 transition-colors"
            >
              <ArrowLeft size={20} />
            </button>
            <div>
              <h1 className="text-2xl font-black text-slate-900 tracking-tighter">
                {isOwnGallery ? 'My Gallery' : `${posts[0]?.user.name || 'User'}'s Gallery`}
              </h1>
              {!isOwnGallery && (
                <div className="flex items-center gap-1 text-[10px] font-bold text-emerald-500 uppercase tracking-widest">
                  <Shield size={10} /> Connected Traveler
                </div>
              )}
            </div>
          </div>

          {isOwnGallery && (
            <button
              onClick={() => setShowUploadModal(true)}
              className="bg-indigo-600 text-white p-3 rounded-full shadow-lg shadow-indigo-200 hover:bg-slate-900 hover:scale-110 active:scale-95 transition-all"
            >
              <Plus size={24} />
            </button>
          )}
        </div>
      </div>

      <main className="max-w-3xl mx-auto px-6 py-12">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-40 gap-4">
            <Loader2 className="w-10 h-10 text-indigo-500 animate-spin" />
            <p className="text-slate-400 font-bold animate-pulse uppercase tracking-widest text-xs">
              Fetching memories...
            </p>
          </div>
        ) : error ? (
          <div className="text-center py-40 flex flex-col items-center gap-6">
            <div className="w-20 h-20 bg-rose-50 text-rose-500 rounded-full flex items-center justify-center mb-4">
              <X size={40} />
            </div>
            <h2 className="text-2xl font-black text-slate-900 tracking-tighter uppercase">
              Access Denied
            </h2>
            <p className="text-slate-500 font-medium max-w-sm mx-auto">{error}</p>
            <button
              onClick={() => navigate(-1)}
              className="mt-4 px-8 py-3 bg-slate-900 text-white rounded-full font-bold uppercase tracking-widest text-xs hover:bg-indigo-600 transition-all"
            >
              Go Back
            </button>
          </div>
        ) : posts.length > 0 ? (
          <div className="space-y-12">
            {posts.map(post => (
              <div
                key={post._id}
                className="bg-white rounded-[2.5rem] overflow-hidden border border-slate-100 shadow-xl shadow-slate-200/40 group transition-all hover:shadow-2xl"
              >
                {/* Post User Header */}
                <div className="p-6 pb-2 flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-2xl overflow-hidden border-2 border-indigo-50 bg-slate-100 shadow-sm">
                      {post.user.avatar ? (
                        <img
                          src={post.user.avatar}
                          alt={post.user.name}
                          className="w-full h-full object-cover"
                        />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-slate-400 bg-white">
                          <User size={24} />
                        </div>
                      )}
                    </div>
                    <div>
                      <h3 className="font-black text-slate-900 leading-tight">{post.user.name}</h3>
                      <div className="flex items-center gap-2 mt-0.5">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
                          <Clock size={10} className="text-slate-300" />
                          {formatRelativeTime(post.createdAt)}
                        </span>
                        {post.tripName && (
                          <>
                            <span className="text-slate-200 text-[10px]">•</span>
                            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest flex items-center gap-1">
                              <MapPin size={10} className="text-indigo-300" />
                              {post.tripName}
                            </span>
                          </>
                        )}
                      </div>
                    </div>
                  </div>

                  <div className="flex gap-1">
                    <button className="p-2.5 text-slate-300 hover:bg-rose-50 hover:text-rose-500 rounded-full transition-all">
                      <Heart size={20} />
                    </button>
                    <button className="p-2.5 text-slate-300 hover:bg-indigo-50 hover:text-indigo-500 rounded-full transition-all">
                      <Share2 size={20} />
                    </button>
                  </div>
                </div>

                {/* Post Image */}
                <div className="p-6 pt-4">
                  <div className="aspect-video w-full rounded-4xl overflow-hidden relative bg-slate-100 shadow-inner">
                    <img
                      src={post.image}
                      alt={post.caption || 'Trip photo'}
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-1000"
                    />
                    <div className="absolute inset-0 bg-linear-to-t from-slate-900/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none p-8 flex items-end">
                      <p className="text-white text-xs font-bold uppercase tracking-widest opacity-80">
                        Capture your moment
                      </p>
                    </div>
                  </div>
                </div>

                {/* Post Caption / Bio */}
                {post.caption && (
                  <div className="px-10 pb-10">
                    <div className="h-px w-8 bg-indigo-100 mb-6 group-hover:w-16 transition-all duration-700"></div>
                    <p className="text-slate-600 font-medium leading-relaxed italic text-lg drop-shadow-sm">
                      "{post.caption}"
                    </p>
                  </div>
                )}
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-40 flex flex-col items-center gap-8">
            <div className="w-40 h-40 bg-white rounded-full flex items-center justify-center border border-slate-100 shadow-xl relative group">
              <div className="absolute inset-0 bg-indigo-50 rounded-full animate-ping opacity-20 scale-125"></div>
              <ImageIcon
                size={64}
                className="text-slate-200 group-hover:text-indigo-200 transition-colors"
              />
            </div>
            <div className="space-y-2">
              <p className="font-black text-2xl text-slate-400 uppercase tracking-tighter">
                Gallery is Quiet
              </p>
              <p className="text-slate-400 font-medium max-w-xs mx-auto">
                Click the button above to share your first travel story!
              </p>
            </div>
          </div>
        )}
      </main>

      {/* Upload Modal */}
      {showUploadModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6">
          <div
            className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-300"
            onClick={() => !isUploading && setShowUploadModal(false)}
          />

          <div className="bg-white w-full max-w-xl rounded-[3rem] p-10 shadow-2xl relative z-10 animate-in zoom-in slide-in-from-bottom-12 duration-500">
            <button
              onClick={() => setShowUploadModal(false)}
              disabled={isUploading}
              className="absolute top-8 right-8 p-3 hover:bg-slate-50 rounded-full text-slate-400 hover:text-rose-500 transition-all"
            >
              <X size={20} />
            </button>

            <div className="mb-10">
              <h2 className="text-4xl font-black text-slate-900 tracking-tighter">Share Memory</h2>
              <p className="text-slate-400 font-medium mt-1">
                Post a beautiful moment from your trip.
              </p>
            </div>

            <form onSubmit={handlePostSubmit} className="space-y-8">
              {/* Image Upload Area */}
              <div
                onClick={() => !isUploading && fileInputRef.current?.click()}
                className={`aspect-video w-full rounded-[2.5rem] border-2 border-dashed transition-all flex flex-col items-center justify-center cursor-pointer overflow-hidden relative shadow-inner
                                    ${uploadData.image ? 'border-indigo-500 bg-indigo-50/10' : 'border-slate-200 bg-slate-50 hover:border-indigo-400 hover:bg-slate-100'}`}
              >
                {uploadData.image ? (
                  <div className="w-full h-full">
                    <img
                      src={uploadData.image}
                      alt="Preview"
                      className="w-full h-full object-cover"
                    />
                    <div className="absolute inset-0 bg-slate-900/60 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity">
                      <p className="text-white font-black text-xs uppercase tracking-widest bg-white/10 px-6 py-3 rounded-full backdrop-blur-md border border-white/20">
                        Change Photo
                      </p>
                    </div>
                  </div>
                ) : (
                  <>
                    {isUploading ? (
                      <div className="flex flex-col items-center gap-3">
                        <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
                        <p className="text-indigo-600 font-black text-[10px] uppercase tracking-widest">
                          Uploading...
                        </p>
                      </div>
                    ) : (
                      <>
                        <div className="bg-white p-5 rounded-4xl shadow-lg border border-slate-100 text-indigo-500 mb-4 group-hover:rotate-12 transition-transform">
                          <Camera size={38} />
                        </div>
                        <p className="font-black text-slate-800 tracking-tight text-xl">
                          Upload Memory
                        </p>
                        <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mt-1">
                          JPEG, PNG, WebP up to 5MB
                        </p>
                      </>
                    )}
                  </>
                )}
                <input
                  type="file"
                  ref={fileInputRef}
                  className="hidden"
                  accept="image/*"
                  onChange={handleFileChange}
                />
              </div>

              <div className="space-y-5">
                <div className="relative">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2 mb-2">
                    Trip Destination Context
                  </label>
                  <div className="relative">
                    <MapPin className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-indigo-400" />
                    <input
                      type="text"
                      placeholder="e.g. Paris, France"
                      className="w-full pl-14 pr-6 py-4.5 bg-slate-50 border border-slate-100 rounded-3xl outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-500 transition-all font-bold text-slate-700 shadow-sm"
                      value={uploadData.tripName}
                      onChange={e => setUploadData(prev => ({ ...prev, tripName: e.target.value }))}
                    />
                  </div>
                </div>
                <div className="relative">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2 mb-2">
                    Memory / Bio
                  </label>
                  <textarea
                    placeholder="Write a small note about this memory..."
                    rows={3}
                    className="w-full px-6 py-5 bg-slate-50 border border-slate-100  outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-500 transition-all font-bold text-slate-700 resize-none shadow-sm"
                    value={uploadData.caption}
                    onChange={e => setUploadData(prev => ({ ...prev, caption: e.target.value }))}
                  />
                </div>
              </div>

              <button
                type="submit"
                disabled={isUploading || !uploadData.image}
                className="w-full py-6 bg-slate-900 text-white rounded-4xl font-black uppercase tracking-[0.3em] text-[10px] shadow-2xl shadow-indigo-200/50 hover:bg-indigo-600 transition-all disabled:opacity-30 active:scale-95 group"
              >
                {isUploading ? (
                  'Posting Story...'
                ) : (
                  <span className="flex items-center justify-center gap-2">
                    Post Memory{' '}
                    <Plus size={16} className="group-hover:rotate-90 transition-transform" />
                  </span>
                )}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default GalleryPage;

import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Send,
  X,
  User,
  AlertCircle,
  Eye,
  ChevronLeft,
  Loader2,
  Plane,
  Smile,
  Image as ImageIcon,
  ChevronDown,
  Sparkles,
  CreditCard,
  ShieldCheck,
  Settings,
  Bot,
  Calendar,
  Lock,
  MapPin,
  Star,
  Clock,
} from 'lucide-react';
import EmojiPicker, { Theme } from 'emoji-picker-react';
import type { EmojiClickData } from 'emoji-picker-react';
import { useSocketContext } from '../../context/SocketContext';
import { authService } from '../../services/c.authService';
import { tripService } from '../../services/c.trip.service';
import api from '../../utils/api';
import type { ITrip, IGuide } from '../../interface/ITripdetails';
import toast from 'react-hot-toast';
import { paymentService } from '../../services/c.payment.service';
import { TripStatus } from '../../constants/TripStatus';
import type { IMessage } from '../../interface/IMessage';
import ReviewModal from '../../components/ReviewModal';
import { ConfirmModal } from '../../components/ConfirmModal';

const GroupChatPage = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [trip, setTrip] = useState<ITrip | null>(null);
  const [messages, setMessages] = useState<IMessage[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(true);
  const [hasPaidDeposit, setHasPaidDeposit] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [showFinalizeModal, setShowFinalizeModal] = useState(false);
  const [showItineraryModal, setShowItineraryModal] = useState(false);
  const [finalizeData, setFinalizeData] = useState({ budget: 0, depositAmount: 0 });
  const [isEditingBudget, setIsEditingBudget] = useState(false);
  const [newBudget, setNewBudget] = useState(0);
  const [isUpdatingBudget, setIsUpdatingBudget] = useState(false);
  const [isFinalizing, setIsFinalizing] = useState(false);
  const [isProcessingPayment, setIsProcessingPayment] = useState(false);
  const [showMembersModal, setShowMembersModal] = useState(false);
  const [showEmojiPicker, setShowEmojiPicker] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [showRecommendationsModal, setShowRecommendationsModal] = useState(false);
  const [recommendedGuides, setRecommendedGuides] = useState<IGuide[]>([]);
  const [isRecommendationsLoading, setIsRecommendationsLoading] = useState(false);
  const [showReviewModal, setShowReviewModal] = useState(false);
  const [reviewTarget, setReviewTarget] = useState<'organizer' | 'guide'>('organizer');

  const [chatPage, setChatPage] = useState(1);
  const [hasMoreMessages, setHasMoreMessages] = useState(false);
  const [isLoadingMore, setIsLoadingMore] = useState(false);
  const MESSAGES_LIMIT = 50;

  const [showConfirmModal, setShowConfirmModal] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const { socket, setCurrentChatId } = useSocketContext();
  const currentUser = authService.getCurrentUser();
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [showScrollButton, setShowScrollButton] = useState(false);
  const isUserScrollingUp = useRef(false);
  const isFirstLoad = useRef(true);

  const handleScroll = () => {
    if (!scrollContainerRef.current) return;
    const { scrollTop, scrollHeight, clientHeight } = scrollContainerRef.current;
    const fromBottom = scrollHeight - scrollTop - clientHeight;

    // more intentional threshold (200px)
    if (fromBottom > 200) {
      isUserScrollingUp.current = true;
      setShowScrollButton(true);
    } else {
      isUserScrollingUp.current = false;
      setShowScrollButton(false);
    }
  };

  const scrollToBottom = (force = false) => {
    setTimeout(() => {
      if (!scrollContainerRef.current) return;
      if (!force && isUserScrollingUp.current) return;

      scrollContainerRef.current.scrollTo({
        top: scrollContainerRef.current.scrollHeight,
        behavior: force ? 'auto' : 'smooth',
      });
    }, 50);
  };

  useEffect(() => {
    const loadInitialData = async () => {
      if (!id) return;
      try {
        const [tripData, historyRes] = await Promise.all([
          tripService.getTripById(id),
          tripService.getChatHistory(id, 1, MESSAGES_LIMIT),
        ]);
        setTrip(tripData);
        setMessages(historyRes.messages);
        setHasMoreMessages(historyRes.total > MESSAGES_LIMIT);

        if (currentUser) {
          const myPayments = await paymentService.getMyPayments(id);
          const paid = myPayments.some(p => p.status === 'escrowed');
          setHasPaidDeposit(paid);
        }

        // Initialize finalizeData from trip (default deposit is 20%)
        setFinalizeData({
          budget: tripData.budget || 0,
          depositAmount: Math.round((tripData.budget || 0) * 0.2),
        });

        // Let the messages effect handle the initial scroll
      } catch (error) {
        console.error('Failed to load chat data:', error);
        toast.error('Failed to load conversation');
        navigate('/dashboard');
      } finally {
        setLoading(false);
      }
    };
    loadInitialData();
  }, [id, navigate, currentUser?.id]);

  useEffect(() => {
    if (!id) return;
    setCurrentChatId(id);
    return () => {
      setCurrentChatId(null);
    };
  }, [id, setCurrentChatId]);

  useEffect(() => {
    if (!socket || !id) return;
    socket.emit('join_trip', id);
  }, [socket, id]);

  const loadMoreMessages = async () => {
    if (!id || isLoadingMore || !hasMoreMessages) return;

    try {
      setIsLoadingMore(true);
      const nextPage = chatPage + 1;
      const res = await tripService.getChatHistory(id, nextPage, MESSAGES_LIMIT);

      setMessages(prev => [...res.messages, ...prev]);
      setChatPage(nextPage);
      setHasMoreMessages(res.total > nextPage * MESSAGES_LIMIT);

      if (scrollContainerRef.current) {
        const prevHeight = scrollContainerRef.current.scrollHeight;
        setTimeout(() => {
          if (scrollContainerRef.current) {
            const newHeight = scrollContainerRef.current.scrollHeight;
            scrollContainerRef.current.scrollTop = newHeight - prevHeight;
          }
        }, 0);
      }
    } catch (err) {
      toast.error('Failed to load older messages');
    } finally {
      setIsLoadingMore(false);
    }
  };

  useEffect(() => {
    if (!socket) return;
    const pageMessageHandler = (message: IMessage) => {
      setMessages(prev => [...prev, message]);
    };

    socket.on('receive_message', pageMessageHandler);
    return () => {
      socket.off('receive_message', pageMessageHandler);
    };
  }, [socket]);

  useEffect(() => {
    if (messages.length > 0) {
      if (isFirstLoad.current) {
        isFirstLoad.current = false;
        scrollToBottom(true); // force on initial load only
        return;
      }
      scrollToBottom(false); // For new messages, only if at bottom
    }
  }, [messages]);

  useEffect(() => {
    const queryParams = new URLSearchParams(window.location.search);
    const sessionId = queryParams.get('session_id');
    if (sessionId && id) {
      const verifyPayment = async () => {
        try {
          await paymentService.verifyStripePayment({ sessionId, tripId: id });
          setHasPaidDeposit(true);
          toast.success('Spot secured!');
          window.history.replaceState({}, document.title, window.location.pathname);
        } catch (error) {
          toast.error('Payment verification failed.');
          window.history.replaceState({}, document.title, window.location.pathname);
        }
      };
      verifyPayment();
    }
  }, [id]);

  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!socket || !newMessage.trim() || !currentUser || !id) return;
    socket.emit('send_message', {
      tripId: id,
      senderId: currentUser.id,
      content: newMessage.trim(),
    });
    setNewMessage('');
    // When sending, force scroll to bottom
    scrollToBottom(true);
  };

  const onEmojiClick = (emojiData: EmojiClickData) => {
    setNewMessage(prev => prev + emojiData.emoji);
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !id || !currentUser) return;
    try {
      setIsUploading(true);
      const formData = new FormData();
      formData.append('chat', file);
      const response = await api.post('/api/chat-image', formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      if (response.data.success) {
        socket?.emit('send_message', {
          tripId: id,
          senderId: currentUser.id,
          content: 'Shared an image',
          messageType: 'image',
          fileUrl: response.data.data.imageUrl,
        });
        scrollToBottom(true);
      } else {
        toast.error('Failed to upload image');
      }
    } catch (error) {
      toast.error('Error uploading image');
    } finally {
      setIsUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handlePayment = async () => {
    if (!trip || !id) return;
    const depositAmount = trip.depositAmount || (trip.budget * 0.2);
    try {
      setIsProcessingPayment(true);
      const { url } = await paymentService.createStripeSession(depositAmount, id);
      if (url) window.location.href = url;
      else setIsProcessingPayment(false);
    } catch (error) {
      toast.error('Payment failed.');
      setIsProcessingPayment(false);
    }
  };

  const handleWalletPayment = async () => {
    if (!trip || !id || !currentUser) return;
    const depositAmount = trip.depositAmount || (trip.budget * 0.2);

    const currentBalance = currentUser.walletBalance || 0;
    if (currentBalance < depositAmount) {
      toast.error('Insufficient wallet balance');
      return;
    }

    try {
      setIsProcessingPayment(true);
      await paymentService.payWithWallet(id, depositAmount);

      // Refresh local user data to update wallet balance in UI
      await authService.getProfile(currentUser.id);

      setHasPaidDeposit(true);
      setShowPaymentModal(false);
      toast.success('Spot secured via wallet!');
    } catch (error) {
      toast.error('Wallet payment failed.');
    } finally {
      setIsProcessingPayment(false);
    }
  };

  const handleFinalizeTrip = async () => {
    if (!id) return;
    try {
      setIsFinalizing(true);
      const response = await api.post(`/api/plantrips/${id}/finalize`, finalizeData);
      if (response.data.success) {
        setTrip(response.data.data);
        setShowFinalizeModal(false);
        toast.success('Trip finalized! Members can now pay deposits.');
      }
    } catch (error) {
      toast.error('Failed to finalize trip.');
    } finally {
      setIsFinalizing(false);
    }
  };

  const handleEditBudget = async () => {
    if (!id || newBudget <= 0) return;
    try {
      setIsUpdatingBudget(true);
      const updatedTrip = await tripService.updateTrip(id, { budget: newBudget });
      setTrip(updatedTrip);
      setIsEditingBudget(false);
      toast.success('Budget updated successfully!');
    } catch (error) {
      toast.error('Failed to update budget');
    } finally {
      setIsUpdatingBudget(false);
    }
  };

  const handleCompleteTrip = async () => {
    if (!id) return;

    try {
      const updatedTrip = await tripService.completeTrip(id);
      setTrip(updatedTrip);
      toast.success('Trip marked as completed!');
      setShowConfirmModal(false);
    } catch (error) {
      toast.error('Failed to complete trip');
    }
  };

  const fetchRecommendations = async () => {
    if (!trip?.destination) return;
    try {
      setIsRecommendationsLoading(true);
      setShowRecommendationsModal(true);
      const res = await api.get('/api/guides/all', {
        params: {
          destination: trip.destination.split(',')[0], // Use major city name
          limit: 5,
        },
      });
      setRecommendedGuides(res.data.data.guides);
    } catch (error) {
      toast.error('Failed to fetch recommendations');
    } finally {
      setIsRecommendationsLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <Loader2 className="w-10 h-10 text-indigo-600 animate-spin" />
      </div>
    );
  }

  if (!trip) return null;

  const organizerId = typeof trip.userId === 'string' ? trip.userId : trip.userId?._id;
  const isOwner = currentUser?.id === organizerId;
  const isGuide =
    currentUser?.id ===
    (typeof trip.guideId?.userId === 'object' ? trip.guideId.userId?._id : trip.guideId?.userId);

  return (
    <div className="h-screen bg-slate-100 flex flex-col font-sans overflow-hidden">
      {/* Centered Header */}
      <div className="bg-white border-b border-slate-200 px-6 py-4 shadow-sm z-20 flex-shrink-0">
        <div className="max-w-5xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button
              onClick={() => navigate(-1)}
              className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500"
            >
              <ChevronLeft size={24} />
            </button>
            <div
              className="flex items-center gap-3 cursor-pointer p-2 hover:bg-slate-50 rounded-xl transition-colors"
              onClick={() => setShowMembersModal(true)}
            >
              <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-100">
                <Plane size={24} />
              </div>
              <div>
                <h1 className="text-xl font-bold text-slate-900">
                  {trip.title || `${trip.destination} Group`}
                </h1>
                <p className="text-xs text-slate-500 font-medium">
                  {trip.members?.length || 0} Members active
                </p>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-3">
            {isOwner && (
              <button
                onClick={() => navigate(`/manage-trip/${id}`)}
                className="hidden md:flex p-2 bg-indigo-50 text-indigo-600 rounded-xl items-center justify-center hover:bg-indigo-100 transition-all font-bold border border-indigo-100 shadow-sm"
                title="Manage Trip"
              >
                <Settings size={18} />
              </button>
            )}
            {trip?.status === TripStatus.PLANNED && isOwner && (
              <button
                onClick={() => setShowFinalizeModal(true)}
                className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 transition-all shadow-sm"
              >
                Finalize Trip
              </button>
            )}
            {/* Trip Status Badge */}
            {new Date(new Date(trip?.startDate || '').getTime() + 3 * 24 * 60 * 60 * 1000) <
              new Date() &&
              trip?.status !== TripStatus.CONFIRMED &&
              trip?.status !== TripStatus.COMPLETED &&
              trip?.status !== TripStatus.CANCELLED && (
                <div className="px-4 py-2 bg-rose-50 text-rose-600 border border-rose-100 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2">
                  <AlertCircle size={14} /> EXPIRED
                </div>
              )}
            {trip?.status === TripStatus.PLANNED && new Date(trip?.startDate || '') >= new Date() && (
              <div className="px-4 py-2 bg-indigo-50 text-indigo-600 border border-indigo-100 rounded-xl text-xs font-bold flex items-center gap-2">
                <Sparkles size={14} /> Awaiting Finalization
              </div>
            )}
            {trip?.status === TripStatus.FINALIZED && (
              <button
                onClick={() => !hasPaidDeposit && setShowPaymentModal(true)}
                className={`px-4 py-2 rounded-xl text-xs font-bold flex items-center gap-2 border transition-all ${hasPaidDeposit
                    ? 'bg-emerald-50 text-emerald-600 border-emerald-100'
                    : 'bg-rose-50 text-rose-600 border-rose-100 animate-pulse'
                  }`}
              >
                {hasPaidDeposit ? <ShieldCheck size={14} /> : <AlertCircle size={14} />}
                {hasPaidDeposit ? 'Spot Secured' : 'Secure Spot'}
              </button>
            )}
            {trip?.status === TripStatus.CONFIRMED && (
              <div className="flex items-center gap-3">
                <div className="px-4 py-2 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-xl text-xs font-bold flex items-center gap-2">
                  <ShieldCheck size={14} /> Confirmed ✅
                </div>
                {isOwner && (
                  <button
                    onClick={() => setShowConfirmModal(true)}
                    className="px-4 py-2 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-slate-800 transition-all shadow-sm"
                  >
                    Complete Trip
                  </button>
                )}
              </div>
            )}
            {trip?.status === TripStatus.COMPLETED && (
              <button
                onClick={() => {
                  if (isOwner) {
                    if (trip.guideId) {
                      setReviewTarget('guide');
                      setShowReviewModal(true);
                    } else {
                      toast.error('No guide to review for this trip.');
                    }
                  } else {
                    setReviewTarget('organizer');
                    setShowReviewModal(true);
                  }
                }}
                className="px-4 py-2 bg-amber-50 text-amber-600 border border-amber-100 rounded-xl text-xs font-bold flex items-center gap-2 hover:bg-amber-100 transition-all"
              >
                <Star size={14} className="fill-amber-600" />
                {isOwner ? 'Review Guide' : 'Review Trip'}
              </button>
