            </p>
          </div>
        </div>
      )}

      {showReviewModal && trip && (
        <ReviewModal
          tripId={trip._id}
          target={reviewTarget}
          targetName={
            reviewTarget === 'organizer'
              ? typeof trip.userId !== 'string'
                ? trip.userId.name
                : 'Organizer'
              : trip.guideId?.name
          }
          onClose={() => setShowReviewModal(false)}
          onSuccess={() => { }}
