// client/src/modules/auth/pages/GuideRegistrationPage.tsx
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { authService } from '../../services/c.authService';
import { Camera, MapPin, IndianRupee, ArrowLeft, Loader2 } from 'lucide-react';
import { GuideStatusPage } from './GuideStatusPage';
import { Navigate } from 'react-router-dom';
import api from '../../utils/api';

// const API_URL = import.meta.env.VITE_API_URL;

const SPECIALTIES = [
  { id: 'food', label: 'Food Tours' },
  { id: 'history', label: 'History & Culture' },
  { id: 'adventure', label: 'Adventure & Hiking' },
  { id: 'nightlife', label: 'Nightlife' },
];

export const GuideRegistrationPage = () => {
  const navigate = useNavigate();
  const user = authService.getCurrentUser();
  console.log('user from guideRegistractionpage ', user);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [preview, setPreview] = useState<string | null>(null);
  const [appStatus, setAppStatus] = useState<'none' | 'pending' | 'verified' | 'loading'>(
    'loading'
  );

  const [formData, setFormData] = useState({
    bio: '',
    hourlyRate: '',
    serviceArea: '',
    specialties: [] as string[],
    avatarFile: null as File | null,
    yearsOfExperience: '',
  });

  const [errors, setErrors] = useState({
    bio: '',
    hourlyRate: '',
    serviceArea: '',
    specialties: '',
    avatarFile: '',
    yearsOfExperience: '',
  });

  useEffect(() => {
    const checkStatus = async () => {
      if (!user) {
        setAppStatus('none');
        return;
      }
      try {
        const res = await api.get(`/api/guides/status/${user.id}`);
        if (res.data.data.exists) {
          setAppStatus(res.data.data.isVerified ? 'verified' : 'pending');
        } else {
          setAppStatus('none');
        }
      } catch (err) {
        setAppStatus('none');
      }
    };
    checkStatus();
  }, [user]);

  if (appStatus === 'loading') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 className="w-12 h-12 text-tb-purple animate-spin mb-4" />
        <p className="text-gray-500 font-medium">Checking application status...</p>
      </div>
    );
  }

  if (appStatus === 'pending') return <GuideStatusPage />;
  if (appStatus === 'verified') return <Navigate to="/guide-dashboard" replace />;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setFormData({ ...formData, avatarFile: file });
      setPreview(URL.createObjectURL(file));
      if (errors.avatarFile) setErrors({ ...errors, avatarFile: '' });
    }
  };

  const handleSpecialtyChange = (id: string) => {
    setFormData(prev => {
      const newSpecialties = prev.specialties.includes(id)
        ? prev.specialties.filter(s => s !== id)
        : [...prev.specialties, id];

      if (errors.specialties) setErrors({ ...errors, specialties: '' });
      return { ...prev, specialties: newSpecialties };
    });
  };

  const validateForm = () => {
    let isValid = true;
    const newErrors = {
      bio: '',
      hourlyRate: '',
      serviceArea: '',
      specialties: '',
      avatarFile: '',
      yearsOfExperience: '',
    };

    if (!formData.bio.trim()) {
      newErrors.bio = 'Summary is required';
      isValid = false;
    } else if (formData.bio.length < 50) {
      newErrors.bio = 'Summary must be at least 50 characters';
      isValid = false;
    }

    if (!formData.hourlyRate) {
      newErrors.hourlyRate = 'Hourly rate is required';
      isValid = false;
    } else if (Number(formData.hourlyRate) <= 0) {
      newErrors.hourlyRate = 'Rate must be greater than 0';
      isValid = false;
    }

    if (!formData.serviceArea.trim()) {
      newErrors.serviceArea = 'Service area is required';
      isValid = false;
    }

    if (!formData.yearsOfExperience) {
      newErrors.yearsOfExperience = 'Years of experience is required';
      isValid = false;
    } else if (Number(formData.yearsOfExperience) < 0) {
      newErrors.yearsOfExperience = 'Experience cannot be negative';
      isValid = false;
    }

    if (formData.specialties.length === 0) {
      newErrors.specialties = 'Select at least one specialty';
      isValid = false;
    }

    if (!formData.avatarFile) {
      newErrors.avatarFile = 'Profile photo is required';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return toast.error('Please login first');
    if (!validateForm()) return;

    setIsSubmitting(true);
    const t = toast.loading('Submitting application...');

    try {
      const data = new FormData();
      const token = authService.getToken();
      if (!token) {
        toast.error('Session expired. please login again', { id: t });
        setIsSubmitting(false);
        return;
      }
      data.append('userId', user.id);
      data.append('bio', formData.bio);
      data.append('hourlyRate', formData.hourlyRate);
      data.append('serviceArea', formData.serviceArea);
      data.append('specialties', JSON.stringify(formData.specialties));
      data.append('yearsOfExperience', formData.yearsOfExperience);
      if (formData.avatarFile) data.append('avatar', formData.avatarFile);

      await api.post(`/api/guides/register`, data, {
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'multipart/form-data',
        },
      });
      toast.success('Application submitted!', { id: t });
      setAppStatus('pending');
    } catch (err: unknown) {
      const errorObj = err as { response?: { data?: { message?: string } } };
      const msg = errorObj.response?.data?.message || 'An unexpected error occurred.';
      toast.error(err.response?.data?.message || 'Registration failed', { id: t });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50">
      <header className="bg-white shadow-sm sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-4 h-16 flex items-center justify-between">
          <button
            onClick={() => navigate(-1)}
            className="flex items-center text-gray-600 hover:text-tb-purple"
          >
            <ArrowLeft className="w-5 h-5 mr-2" /> Back
          </button>
          <h1 className="font-bold text-xl">Apply as Local Expert</h1>
          <div className="w-10"></div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto py-10 px-4">
        <form onSubmit={handleSubmit} className="space-y-8" noValidate>
          {/* Section 1: Identity */}
          <div
            className={`bg-white p-8 rounded-2xl shadow-sm border ${
              errors.avatarFile ? 'border-red-500' : 'border-gray-100'
            }`}
          >
            <div className="flex items-center gap-4 mb-6">
              <span className="w-8 h-8 bg-tb-purple text-white rounded-full flex items-center justify-center font-bold">
                1
              </span>
              <h2 className="text-xl font-bold">Profile Identity</h2>
            </div>

            <div className="flex flex-col items-center mb-6">
              <div className="relative group cursor-pointer">
                <div
                  className={`w-24 h-24 rounded-full overflow-hidden border-4 ${
                    errors.avatarFile ? 'border-red-300' : 'border-tb-purple/20'
                  } bg-gray-100`}
                >
                  {preview ? (
                    <img src={preview} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <Camera className="w-8 h-8 m-8 text-gray-400" />
                  )}
                </div>
                <input
                  type="file"
                  onChange={handleFileChange}
                  className="absolute inset-0 opacity-0 cursor-pointer"
                  accept="image/*"
                />
              </div>
              <p className="mt-2 text-sm text-tb-purple font-medium">Upload Professional Photo</p>
              {errors.avatarFile && (
                <p className="mt-1 text-xs text-red-500 font-medium">{errors.avatarFile}</p>
              )}
            </div>
          </div>

          {/* Section 2: Expertise */}
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
            <div className="flex items-center gap-4 mb-6">
              <span className="w-8 h-8 bg-tb-purple text-white rounded-full flex items-center justify-center font-bold">
                2
              </span>
              <h2 className="text-xl font-bold">Expertise & Rate</h2>
            </div>

            <div className="grid gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Guiding Summary
                </label>
                <textarea
                  className={`w-full p-3 border ${
                    errors.bio ? 'border-red-500' : 'border-gray-200'
                  } rounded-xl focus:ring-2 focus:ring-tb-purple outline-none transition-all`}
                  rows={3}
                  placeholder="Tell travelers about your local secrets..."
                  value={formData.bio}
                  onChange={e => {
                    setFormData({ ...formData, bio: e.target.value });
                    if (errors.bio) setErrors({ ...errors, bio: '' });
                  }}
                />
                {errors.bio && (
                  <p className="mt-1 text-xs text-red-500 font-medium">{errors.bio}</p>
                )}
              </div>
              <div className="grid md:grid-cols-3 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Hourly Rate (INR)
                  </label>
                  <div className="relative">
                    <IndianRupee className="absolute left-3 top-3 w-5 h-5 text-gray-400" />
                    <input
                      type="number"
                      className={`w-full pl-10 pr-4 py-3 border ${
                        errors.hourlyRate ? 'border-red-500' : 'border-gray-200'
                      } rounded-xl`}
                      placeholder="500"
                      value={formData.hourlyRate}
                      onChange={e => {
                        setFormData({ ...formData, hourlyRate: e.target.value });
                        if (errors.hourlyRate) setErrors({ ...errors, hourlyRate: '' });
                      }}
                    />
                  </div>
                  {errors.hourlyRate && (
                    <p className="mt-1 text-xs text-red-500 font-medium">{errors.hourlyRate}</p>
                  )}
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Service Area
                  </label>
                  <div className="relative">
                    <MapPin className="absolute left-3 top-3 w-5 h-5 text-gray-400" />
                    <input
                      type="text"
                      className={`w-full pl-10 pr-4 py-3 border ${
                        errors.serviceArea ? 'border-red-500' : 'border-gray-200'
                      } rounded-xl`}
                      placeholder="e.g. South Goa"
                      value={formData.serviceArea}
                      onChange={e => {
                        setFormData({ ...formData, serviceArea: e.target.value });
                        if (errors.serviceArea) setErrors({ ...errors, serviceArea: '' });
                      }}
                    />
                  </div>
                  {errors.serviceArea && (
                    <p className="mt-1 text-xs text-red-500 font-medium">{errors.serviceArea}</p>
                  )}
                </div>
                {/* Years of Experience */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Experience (Years)
                  </label>
                  <div className="relative">
                    <input
                      type="number"
                      min="0"
                      className={`w-full px-4 py-3 border ${
                        errors.yearsOfExperience ? 'border-red-500' : 'border-gray-200'
                      } rounded-xl focus:ring-2 focus:ring-tb-purple outline-none`}
                      placeholder="e.g. 5"
                      value={formData.yearsOfExperience}
                      onChange={e => {
                        setFormData({ ...formData, yearsOfExperience: e.target.value });
                        if (errors.yearsOfExperience)
                          setErrors({ ...errors, yearsOfExperience: '' });
                      }}
                    />
                  </div>
                  {errors.yearsOfExperience && (
                    <p className="mt-1 text-xs text-red-500 font-medium">
                      {errors.yearsOfExperience}
                    </p>
                  )}
                </div>
              </div>
            </div>
          </div>

          {/* Section 3: Specialities */}
          <div
            className={`bg-white p-8 rounded-2xl shadow-sm border ${
              errors.specialties ? 'border-red-500' : 'border-gray-100'
            }`}
          >
            <div className="flex items-center gap-4 mb-6">
              <span className="w-8 h-8 bg-tb-purple text-white rounded-full flex items-center justify-center font-bold">
                3
              </span>
              <h2 className="text-xl font-bold">Tour Specialities</h2>
            </div>
            <div className="flex flex-wrap gap-3">
              {SPECIALTIES.map(s => (
                <button
                  key={s.id}
                  type="button"
                  onClick={() => handleSpecialtyChange(s.id)}
                  className={`px-4 py-2 rounded-full border transition-all ${
                    formData.specialties.includes(s.id)
                      ? 'bg-tb-purple text-white border-tb-purple'
                      : 'bg-white text-gray-600 border-gray-200'
                  }`}
                >
                  {s.label}
                </button>
              ))}
            </div>
            {errors.specialties && (
              <p className="mt-3 text-xs text-red-500 font-medium text-center">
                {errors.specialties}
              </p>
            )}
          </div>

          <button
            type="submit"
            disabled={isSubmitting}
            className="w-full py-4 bg-[#10b981] text-white text-lg font-bold rounded-xl shadow-lg hover:bg-emerald-600 transition-colors disabled:opacity-50"
          >
            {isSubmitting ? 'Processing...' : '🚀 Submit Application'}
          </button>
        </form>
      </main>
    </div>
  );
};

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { authService } from '../../services/c.authService';
import api from '../../utils/api';
import { Button } from '../../components/Button';
import toast from 'react-hot-toast';

const KYCPage = () => {
  const [docType, setDocType] = useState('national_id');
  const [file, setFile] = useState<File | null>(null);
  const [error, setError] = useState('');
  const [progress, setProgress] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [checking, setChecking] = useState(true);
  const navigate = useNavigate();
  const user = authService.getCurrentUser();

  useEffect(() => {
    const checkExistingStatus = async () => {
      const userId = user?.id;
      if (userId) {
        try {
          const res = await api.get(`/api/kyc-status/${userId}`);
          const status = res.data.data?.status;
          if (status === 'pending' || status === 'approved') {
            navigate('/kyc-status');
          }
        } catch (err) {
          console.error('Error checking status on load');
        } finally {
          setChecking(false);
        }
      } else {
        setChecking(false);
      }
    };
    checkExistingStatus();
  }, [user?.id, navigate]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setError('');
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!file) {
      setError('Please upload a document to proceed');
      return;
    }

    const userId = user?.id;
    if (!userId) {
      toast.error('User session not found. Please log in again.');
      return;
    }

    console.log('Submitting KYC:', { userId, documentType: docType, fileName: file.name });

    setIsSubmitting(true);
    const formData = new FormData();
    formData.append('userId', userId);
    formData.append('documentType', docType);
    formData.append('image', file);

    try {
      const response = await api.post(`/api/upload`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
        onUploadProgress: (progressEvent: any) => {
          const percentCompleted = Math.round(
            (progressEvent.loaded * 100) / (progressEvent.total || 1)
          );
          setProgress(percentCompleted);
        },
      });

      if (response.status === 201) {
        toast.success('KYC submitted successfully 🎉');
        setTimeout(() => navigate('/kyc-status'), 1500);
      }
    } catch (error) {
      console.error('Upload failed:', error);
      toast.error('Error uploading document. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (checking)
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-gray-500 font-medium">Checking verification status...</div>
      </div>
    );

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center py-12 px-4">
      <div className="max-w-md w-full bg-white rounded-2xl shadow-xl p-8">
        <h2 className="text-2xl font-bold text-gray-900 mb-2">Verify your identity</h2>
        <p className="text-gray-500 mb-8 text-sm">
          Please upload a clear photo of your government-issued ID to unlock all features.
        </p>

        <form onSubmit={handleSubmit} className="space-y-6" noValidate>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Document Type</label>
            <select
              value={docType}
              onChange={e => setDocType(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-[#5537ee] outline-none"
            >
              <option value="national_id">National ID Card</option>
              <option value="passport">Passport</option>
              <option value="driver_license">Driver's License</option>
            </select>
          </div>

          <div
            className={`relative border-2 border-dashed ${
              error ? 'border-red-500 bg-red-50' : 'border-gray-200 hover:border-[#5537ee]'
            } rounded-2xl p-8 text-center transition-colors`}
          >
            <input
              type="file"
              accept="image/*"
              onChange={handleFileChange}
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
              disabled={isSubmitting}
            />
            <div className="space-y-2">
              <div
                className={`w-12 h-12 rounded-full flex items-center justify-center mx-auto ${
                  error ? 'bg-red-100' : 'bg-indigo-50'
                }`}
              >
                <svg
                  className={`w-6 h-6 ${error ? 'text-red-500' : 'text-[#5537ee]'}`}
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth="2"
                    d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-8l-4-4m0 0L8 8m4-4v12"
                  />
                </svg>
              </div>
              <p className={`text-sm font-medium ${error ? 'text-red-500' : 'text-gray-700'}`}>
                {file ? file.name : error || 'Click to upload or drag and drop'}
              </p>
            </div>
          </div>

          {isSubmitting && (
            <div className="w-full bg-gray-200 rounded-full h-2.5">
              <div
                className="bg-[#5537ee] h-2.5 rounded-full transition-all duration-300"
                style={{ width: `${progress}%` }}
              ></div>
              <p className="text-xs text-center mt-2 text-gray-500">{progress}% Uploaded</p>
            </div>
          )}

          <Button
            type="submit"
            className="w-full py-4 rounded-xl shadow-lg"
            disabled={isSubmitting}
          >
            {isSubmitting ? 'Uploading...' : 'Submit for Verification'}
          </Button>

          <button
            type="button"
            onClick={() => navigate('/')}
            className="w-full text-center text-sm text-gray-500 hover:text-gray-700 font-medium"
          >
            Skip for now
          </button>
        </form>
      </div>
    </div>
  );
};

export default KYCPage;

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../utils/api';
import { authService } from '../../services/c.authService';

