          <button
            onClick={() => authService.logout()}
            className="w-full mt-8 py-3 bg-green-600 text-white rounded-xl font-semibold hover:bg-green-700 hover:shadow-lg transition flex items-center justify-center gap-2"
          >
            Go to Login
          </button>
        )} */}

        <button
