import toast from 'react-hot-toast';

const ProfilePage = () => {
  const navigate = useNavigate();
  const [currentUser, setCurrentUser] = useState(authService.getCurrentUser());

  const [kycStatus, setKycStatus] = useState<string>('loading');
  const [requests, setRequests] = useState<ConnectionRequest[]>([]);
  const [activeTab, setActiveTab] = useState<'planned' | 'requested' | 'chats'>('planned');
  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState({
    name: currentUser?.name || '',
    bio: currentUser?.bio || '',
  });
  const [isSaving, setIsSaving] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [isPasswordModalOpen, setIsPasswordModalOpen] = useState(false);
  const [passwordData, setPasswordData] = useState({
    oldPassword: '',
    newPassword: '',
    confirmPassword: '',
  });
  const [isChangingPassword, setIsChangingPassword] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [errors, setErrors] = useState<{
    name?: string;
    bio?: string;
    oldPassword?: string;
    newPassword?: string;
    confirmPassword?: string;
  }>({});

  const clearError = (field: string) => {
    setErrors(prev => {
      const newErrors = { ...prev };
      delete (newErrors as Record<string, string>)[field];
      return newErrors;
    });
  };

  useEffect(() => {
    const loadInitialData = async () => {
      if (!currentUser?.id) return;
      try {
        console.log('current user', currentUser);
        const [kycRes, reqData, profileData] = await Promise.all([
          api.get(`/api/kyc-status/${currentUser.id}`),
          connectionService.getPendingRequests(),
          authService.getProfile(currentUser.id),
        ]);
        setKycStatus(kycRes.data.data?.status || 'none');
        setRequests(reqData);
        setCurrentUser(profileData);
      } catch (err) {
        console.error('Data load failed', err);
      }
    };
    loadInitialData();
  }, [currentUser?.id]);

  if (!currentUser) {
    navigate('/login');
    return null;
  }

  const handleLogout = () => {
    authService.logout();
    navigate('/');
  };

  const handleSave = async () => {
    if (!currentUser?.id) return;

    // Validation
    const newErrors: Record<string, string> = {};
    if (!editData.name.trim()) newErrors.name = 'Name is required';
    if (editData.bio.length > 200) newErrors.bio = 'Bio cannot exceed 200 characters';

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    try {
      setIsSaving(true);
      await authService.updateProfile(currentUser.id, editData);
      toast.success('Profile updated successfully');
      setIsEditing(false);
      setErrors({});
    } catch (error: unknown) {
      console.error('Profile update error', error);
      const err = error as { response?: { data?: { message?: string } } };
      const message = err.response?.data?.message || 'Failed to update profile';
      toast.error(message);
    } finally {
      setIsSaving(false);
    }
  };

  const handlePhotoChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !currentUser?.id) return;
    const formData = new FormData();
    formData.append('avatar', file);
    try {
      setIsUploading(true);
      const res = await api.post('/api/profile-photo', formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      await authService.updateProfile(currentUser.id, { avatarURL: res.data.data.imageUrl });
      toast.success('Profile photo updated successfully');
    } catch (error) {
      toast.error('Upload failed');
    } finally {
      setIsUploading(false);
    }
  };

  const handlePasswordChange = async (e: React.FormEvent) => {
    e.preventDefault();
    const newErrors: Record<string, string> = {};

    if (!passwordData.oldPassword) newErrors.oldPassword = 'Current password is required';
    if (passwordData.newPassword.length < 6)
      newErrors.newPassword = 'Password must be at least 6 characters';
    if (passwordData.newPassword !== passwordData.confirmPassword)
      newErrors.confirmPassword = 'Passwords do not match';

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    try {
      setIsChangingPassword(true);
      await authService.changePassword(currentUser.id!, {
        oldPassword: passwordData.oldPassword,
        newPassword: passwordData.newPassword,
      });
      toast.success('Password changed successfully');
      setIsPasswordModalOpen(false);
      setPasswordData({ oldPassword: '', newPassword: '', confirmPassword: '' });
      setErrors({});
    } catch (err: unknown) {
      const error = err as { response?: { data?: { message?: string } } };
      const message = error.response?.data?.message || 'Failed to change password';

      if (message.toLowerCase().includes('current password')) {
        setErrors({ ...errors, oldPassword: message });
      } else {
        toast.error(message);
      }
    } finally {
      setIsChangingPassword(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Navbar variant="sticky" />

      <main className="grow py-12 px-4">
        <div className="max-w-7xl mx-auto">
          <button
            onClick={() => navigate('/')}
            className="group flex items-center gap-2 px-4 py-2 bg-white text-slate-500 hover:text-indigo-600 rounded-full font-bold text-sm shadow-sm border border-slate-100 transition-all hover:-translate-x-1 mb-6"
          >
            <ArrowLeft
              size={16}
              className="text-slate-400 group-hover:text-indigo-500 transition-colors"
            />
            Back to Home
          </button>

          {/* 1. Identity Section */}
          <section className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100 mb-10">
            <div className="flex flex-col md:flex-row items-center md:items-start gap-8">
              <div className="relative shrink-0">
                <input
                  type="file"
                  className="hidden"
                  ref={fileInputRef}
                  onChange={handlePhotoChange}
                  accept="image/*"
                />
                <div className="w-40 h-40 rounded-full bg-slate-100 flex items-center justify-center overflow-hidden border-4 border-white shadow-lg relative group">
                  {isUploading ? (
                    <Loader2 className="w-8 h-8 text-indigo-500 animate-spin" />
                  ) : currentUser.avatarURL ? (
                    <img
                      src={currentUser.avatarURL}
                      alt=""
                      className="w-full h-full object-cover"
                    />
                  ) : currentUser.name ? (
                    <span className="text-5xl font-bold text-slate-400">{currentUser.name[0]}</span>
                  ) : (
                    <User className="w-20 h-20 text-slate-300" />
                  )}
                  <button
                    onClick={() => fileInputRef.current?.click()}
                    className="absolute inset-0 bg-slate-800/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center text-white"
                  >
                    <Camera size={24} />
                  </button>
                </div>
              </div>

              <div className="flex-1 text-center md:text-left pt-4">
                {isEditing ? (
                  <div className="space-y-4 w-full max-w-md">
                    <div className="flex flex-col gap-1">
                      <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-1">
                        Full Name
                      </label>
                      <input
                        type="text"
                        value={editData.name}
                        onChange={e => {
                          setEditData({ ...editData, name: e.target.value });
                          if (errors.name) clearError('name');
                        }}
                        className={`w-full px-4 py-2 bg-slate-50 border ${errors.name ? 'border-red-300 ring-4 ring-red-50' : 'border-slate-100'} rounded-xl text-2xl font-bold text-slate-800 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all`}
                        placeholder="Your name"
                      />
                      {errors.name && (
                        <p className="text-[10px] text-red-500 font-bold mt-1 pl-1 flex items-center gap-1">
                          <X size={10} /> {errors.name}
                        </p>
                      )}
                    </div>
                    <div className="flex flex-col gap-1">
                      <div className="flex justify-between items-center mb-1">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-1">
                          Bio
                        </label>
                        <span
                          className={`text-[10px] font-bold ${editData.bio.length > 180 ? 'text-amber-500' : 'text-slate-300'}`}
                        >
                          {editData.bio.length}/200
                        </span>
                      </div>
                      <textarea
                        value={editData.bio}
                        onChange={e => {
                          setEditData({ ...editData, bio: e.target.value });
                          if (errors.bio) clearError('bio');
                        }}
                        className={`w-full px-4 py-2 bg-slate-50 border ${errors.bio ? 'border-red-300 ring-4 ring-red-50' : 'border-slate-100'} rounded-xl text-sm font-medium text-slate-600 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all min-h-[100px] resize-none`}
                        placeholder="Tell travelers about yourself..."
                      />
                      {errors.bio && (
                        <p className="text-[10px] text-red-500 font-bold mt-1 pl-1 flex items-center gap-1">
                          <X size={10} /> {errors.bio}
                        </p>
                      )}
                    </div>
                  </div>
                ) : (
                  <>
                    <div className="flex flex-col md:flex-row items-center gap-3 mb-2 text-center md:text-left">
                      <h2 className="text-3xl font-bold text-slate-800">{currentUser.name}</h2>
                      <span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-bold uppercase tracking-widest">
                        {currentUser.role}
                      </span>
                    </div>
                    <p className="text-slate-500 font-medium mb-4 flex items-center justify-center md:justify-start gap-2">
                      <Mail size={16} /> {currentUser.email}
                    </p>
                    {/* <h1>{currentUser.isBlocked}</h1> */}
                    <p className="text-slate-600 text-sm leading-relaxed max-w-xl">
                      {currentUser.bio || 'No biography added yet.'}
                    </p>
                  </>
                )}
              </div>

              <div className="flex flex-col gap-3 shrink-0">
                {isEditing ? (
                  <>
                    <button
                      onClick={handleSave}
                      disabled={isSaving}
                      className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 active:scale-95 disabled:opacity-50"
                    >
                      {isSaving ? (
                        <Loader2 className="animate-spin" size={18} />
                      ) : (
                        <span>Save Changes</span>
                      )}
                    </button>
                    <button
                      onClick={() => {
                        setIsEditing(false);
                        setEditData({ name: currentUser.name, bio: currentUser.bio || '' });
                        setErrors({});
                      }}
                      className="px-8 py-3 bg-white text-slate-400 rounded-xl font-bold hover:bg-slate-50 transition-all border border-slate-100"
                    >
                      Cancel
                    </button>
                  </>
                ) : (
                  <>
                    <button
                      onClick={() => {
                        setIsEditing(true);
                        setErrors({});
                      }}
                      className="px-8 py-3 bg-white text-slate-800 rounded-xl font-bold shadow-sm hover:bg-slate-50 transition-all flex items-center gap-2 border border-slate-100"
                    >
                      <Edit3 size={18} /> Edit Profile
                    </button>
                    <button
