                  <span className="text-sm font-medium text-slate-600">KYC Status</span>
                  <span
                    className={`text-[10px] font-bold px-3 py-1 rounded-md uppercase tracking-widest ${kycStatus === 'approved' ? 'bg-green-50 text-green-600' : 'bg-amber-50 text-amber-600'}`}
                  >
                    {kycStatus}
                  </span>
                </div>
                {requests.length > 0 && (
                  <button
