                <button
                  onClick={() => setActiveTab('requested')}
                  className={`relative py-6 text-sm font-bold transition-all ${
                    activeTab === 'requested'
                      ? 'text-indigo-600'
                      : 'text-slate-400 hover:text-slate-600'
