                <div className="h-6 w-[1.5px] bg-slate-200"></div>
                <button
                  onClick={() => setActiveTab('chats')}
                  className={`relative py-6 text-sm font-bold transition-all ${
                    activeTab === 'chats'
                      ? 'text-indigo-600'
