            <div className="p-8">
              {activeTab === 'planned' ? (
                <PlannedTrips userId={currentUser.id!} />
              ) : activeTab === 'requested' ? (
                <RequestedTrips userId={currentUser.id!} />
              ) : (
                <LiveChats userId={currentUser.id!} />
              )}
            </div>
          </div>
        </div>
      </main>

      <MainFooter />

      {/* Password Change Modal */}
      {isPasswordModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div
            className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm"
            onClick={() => !isChangingPassword && setIsPasswordModalOpen(false)}
          ></div>
          <div className="relative bg-white w-full max-w-md rounded-2xl shadow-2xl border border-slate-100 animate-in zoom-in-95 duration-200 overflow-hidden">
            <div className="p-6">
              <h3 className="text-xl font-bold text-slate-800 mb-2 flex items-center gap-2">
                <Shield size={20} className="text-indigo-500" /> Change Your Password
              </h3>
              <p className="text-xs text-slate-400 font-medium mb-6 uppercase tracking-widest">
                Provide your current and new password below
              </p>

              <form onSubmit={handlePasswordChange} className="space-y-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-1">
                    Current Password
                  </label>
                  <input
                    type="password"
                    required
                    value={passwordData.oldPassword}
                    onChange={e => {
                      setPasswordData({ ...passwordData, oldPassword: e.target.value });
                      if (errors.oldPassword) clearError('oldPassword');
                    }}
                    className={`w-full px-4 py-3 bg-slate-50 border ${errors.oldPassword ? 'border-red-300 ring-4 ring-red-50' : 'border-slate-100'} rounded-xl text-sm font-medium text-slate-800 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all shadow-sm`}
                    placeholder="••••••••"
                  />
                  {errors.oldPassword && (
                    <p className="text-[10px] text-red-500 font-bold mt-1 pl-1 animate-in slide-in-from-left-2">
                      {errors.oldPassword}
                    </p>
                  )}
                </div>

                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-1">
                    New Password
                  </label>
                  <input
                    type="password"
                    required
                    minLength={6}
                    value={passwordData.newPassword}
                    onChange={e => {
                      setPasswordData({ ...passwordData, newPassword: e.target.value });
                      if (errors.newPassword) clearError('newPassword');
                    }}
                    className={`w-full px-4 py-3 bg-slate-50 border ${errors.newPassword ? 'border-red-300 ring-4 ring-red-50' : 'border-slate-100'} rounded-xl text-sm font-medium text-slate-800 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all shadow-sm`}
                    placeholder="Min. 6 characters"
                  />
                  {errors.newPassword && (
                    <p className="text-[10px] text-red-500 font-bold mt-1 pl-1 animate-in slide-in-from-left-2">
                      {errors.newPassword}
                    </p>
                  )}
                </div>

                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-1">
                    Confirm New Password
                  </label>
                  <input
                    type="password"
                    required
                    value={passwordData.confirmPassword}
                    onChange={e => {
                      setPasswordData({ ...passwordData, confirmPassword: e.target.value });
                      if (errors.confirmPassword) clearError('confirmPassword');
                    }}
                    className={`w-full px-4 py-3 bg-slate-50 border ${errors.confirmPassword ? 'border-red-300 ring-4 ring-red-50' : 'border-slate-100'} rounded-xl text-sm font-medium text-slate-800 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all shadow-sm`}
                    placeholder="••••••••"
                  />
                  {errors.confirmPassword && (
                    <p className="text-[10px] text-red-500 font-bold mt-1 pl-1 animate-in slide-in-from-left-2">
                      {errors.confirmPassword}
                    </p>
                  )}
                </div>

                <div className="flex gap-3 pt-4">
                  <button
                    type="button"
                    disabled={isChangingPassword}
                    onClick={() => setIsPasswordModalOpen(false)}
                    className="flex-1 py-3 px-4 bg-slate-50 text-slate-400 rounded-xl font-bold hover:bg-slate-100 transition-all disabled:opacity-50"
                  >
                    Cancel
                  </button>
                  <button
                    type="submit"
                    disabled={isChangingPassword}
                    className="flex-[2] py-3 px-4 bg-indigo-600 text-white rounded-xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 active:scale-95 disabled:opacity-50"
                  >
                    {isChangingPassword ? (
                      <Loader2 className="animate-spin" size={18} />
                    ) : (
                      <span>Change Password</span>
                    )}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ProfilePage;

import { useEffect, useState } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import {
  Sparkles,
  UserCheck,
  Clock,
  UserPlus,
  User,
  Calendar,
  Lock,
  MapPin,
  X,
  MessageCircle,
  AlertCircle,
  Loader2,
} from 'lucide-react';
import { tripService } from '../../services/c.trip.service';
import { connectionService } from '../../services/c.connection.service';
import { authService } from '../../services/c.authService';
import { paymentService } from '../../services/c.payment.service';
import type { ITrip } from '../../interface/ITripdetails';
import { TripStatus } from '../../constants/TripStatus';
import toast from 'react-hot-toast';

const TripDetails = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation();

  const from = location.state?.from || '/find-travelers';

  const [trip, setTrip] = useState<ITrip | null>(null);
  const [loading, setLoading] = useState(true);
  const [status, setStatus] = useState<
    'none' | 'pending' | 'accepted' | 'rejected' | 'incoming_pending' | 'loading'
  >('loading');
  const [hasPaidDeposit, setHasPaidDeposit] = useState(false);
  const [showCancelModal, setShowCancelModal] = useState(false);
  const [isCancelling, setIsCancelling] = useState(false);

  const currentUser = authService.getCurrentUser();

  useEffect(() => {
    const loadTripData = async () => {
      if (!id) return;
      try {
        const data = await tripService.getTripById(id);
        setTrip(data);

        const tripOrganizerId = typeof data.userId === 'string' ? data.userId : data.userId._id;

        if (currentUser?.id && tripOrganizerId !== currentUser.id) {
          const resStatus = await connectionService.getStatus(tripOrganizerId, data._id);
          setStatus(resStatus || 'none');

          if (resStatus === 'accepted') {
            const myPayments = await paymentService.getMyPayments(id);
            const paid = myPayments.some(p => p.status === 'escrowed');
            setHasPaidDeposit(paid);
          }
        } else {
          setStatus('none');
        }
      } catch (error) {
        console.error('Error loading trip details:', error);
        toast.error('Failed to load trip details');
      } finally {
        setLoading(false);
      }
    };

    loadTripData();
  }, [id, currentUser?.id]);

  const handleSendRequest = async () => {
    if (!currentUser?.id) {
      toast.error('Please login to send request');
      navigate('/login');
      return;
    }
    if (!trip) return;

    try {
      const tripOrganizerId = typeof trip.userId === 'string' ? trip.userId : trip.userId._id;
      await connectionService.sendRequest(tripOrganizerId, trip._id);
      setStatus('pending');
      toast.success('Connection request sent!');
    } catch (error) {
      toast.error('Failed to send request');
      setStatus('none');
    }
  };

  const handleCancelTrip = async () => {
    if (!id) return;
    try {
      setIsCancelling(true);
      await tripService.cancelTrip(id);
      toast.success('Trip cancelled and members refunded.');
      if (trip) setTrip({ ...trip, status: TripStatus.CANCELLED });
      setShowCancelModal(false);
    } catch (error) {
      toast.error('Failed to cancel trip');
    } finally {
      setIsCancelling(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center">
        <div className="w-12 h-12 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
      </div>
    );
  }

  if (!trip) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-6">
        <h2 className="text-2xl font-bold text-slate-800 mb-4">Trip not found</h2>
        <button
          onClick={() => navigate(from)}
          className="text-indigo-600 font-bold hover:underline"
        >
          Back
        </button>
      </div>
    );
  }

  const isOwnTrip =
    currentUser?.id === (typeof trip.userId === 'string' ? trip.userId : trip.userId._id);

  return (
    <div className="min-h-screen bg-slate-50 font-sans">
      {/* Container */}
      <div className="max-w-4xl mx-auto bg-white min-h-screen shadow-xl border-x border-slate-100 flex flex-col p-8 md:p-12">
        {/* Header Section */}
        <div className="flex items-center justify-between mb-8 pb-4 border-b border-slate-100">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <MapPin className="text-white w-6 h-6" />
            </div>
            <span className="text-2xl font-black text-slate-900 tracking-tight">Trip Buddy</span>
          </div>
          <button
            onClick={() => navigate(from)}
            className="px-6 py-2 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition flex items-center gap-2 shadow-lg shadow-indigo-100"
          >
            back
          </button>
        </div>

        {/* User Info Section */}
        <div className="flex flex-col md:flex-row gap-8 mb-10">
          <div className="relative shrink-0">
            <img
              src={
                typeof trip.userId !== 'string'
                  ? trip.userId.avatarURL || `https://i.pravatar.cc/300?u=${trip.userId._id}`
                  : `https://i.pravatar.cc/300?u=${trip.userId}`
              }
              className="w-32 h-32 md:w-40 md:h-40 rounded-[2.5rem] object-cover border-4 border-indigo-50 shadow-md"
              alt={typeof trip.userId !== 'string' ? trip.userId.name : 'Organizer'}
            />
          </div>
          <div className="flex flex-col justify-center">
            <h1 className="text-3xl font-black text-slate-900 mb-2">
              {typeof trip.userId !== 'string' ? trip.userId.name : 'Unknown Organizer'}
            </h1>
            <p className="text-slate-500 font-bold mb-4">Age: 23</p>
            <div className="space-y-2">
              <p className="text-slate-700 font-bold flex items-center gap-2 text-lg">
                <span className="text-indigo-600 font-black">Destination:</span>
                {trip.destination}
                <span className="text-slate-400 font-medium">
                  (
                  {new Date(trip.startDate).toLocaleDateString(undefined, {
                    day: 'numeric',
                    month: 'short',
                  })}{' '}
                  -{' '}
                  {new Date(trip.endDate).toLocaleDateString(undefined, {
                    day: 'numeric',
                    month: 'short',
                  })}
                  )
                </span>
              </p>
            </div>

            <div className="flex flex-wrap gap-2 mt-6">
              {trip.preferences.interests.map(interest => (
                <span
                  key={interest}
                  className="px-4 py-1.5 bg-indigo-50 text-indigo-700 rounded-full text-xs font-black uppercase tracking-widest border border-indigo-100"
                >
                  {interest}
                </span>
              ))}
            </div>
          </div>
        </div>

        {/* Travel Preferences Section */}
        <div className="bg-white rounded-3xl p-8 border border-slate-200 shadow-sm mb-auto">
          <h2 className="text-xl font-black text-slate-900 mb-6 flex items-center gap-2">
            <Sparkles className="text-indigo-500 w-5 h-5" /> Travel Preferences
          </h2>

          <div className="space-y-6">
            <div className="flex items-center justify-between group">
              <div className="flex flex-col">
                <span className="text-sm font-black text-slate-900">Budget</span>
                <p className="text-slate-500 font-medium mt-1">₹ {trip.budget} </p>
              </div>
            </div>

            <div className="flex items-center justify-between group">
              <div className="flex flex-col">
                <span className="text-sm font-black text-slate-900">Transport</span>
                <p className="text-slate-500 font-medium mt-1 uppercase tracking-wider">
                  {trip.preferences.transport}
                </p>
              </div>
            </div>

            <div className="flex items-center justify-between group">
              <div className="flex flex-col">
                <span className="text-sm font-black text-slate-900">discription</span>
                <p className="text-slate-500 font-medium mt-1">{trip.description}</p>
              </div>
            </div>
            <div>
              <h5 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-3 flex items-center gap-2">
                <User size={12} /> Trip Members ({trip.members?.length || 0})
              </h5>
              <div className="flex flex-wrap gap-2">
                {trip.members && trip.members.length > 0 ? (
                  trip.members.map(member => (
                    <div
                      key={member._id}
                      className="flex items-center gap-2 bg-white p-1.5 rounded-full border border-slate-100 shadow-sm pr-3"
                    >
                      <img
                        src={member.avatarURL || `https://ui-avatars.com/api/?name=${member.name}`}
                        alt=""
                        className="w-6 h-6 rounded-full object-cover"
                      />
                      <span className="text-xs font-bold text-slate-700">{member.name}</span>
                    </div>
                  ))
                ) : (
                  <p className="text-xs text-slate-400 italic">No members yet</p>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Action Button Section */}
        <div className="mt-8">
          {isOwnTrip ? (
            <div className="space-y-4">
              {trip.status === TripStatus.CANCELLED && (
                <button
                  disabled
                  className="w-full py-5 bg-rose-50 text-rose-600 border-2 border-rose-200 rounded-2xl font-black uppercase tracking-[0.2em]"
                >
                  Trip Cancelled
                </button>
              )}
              {(trip.status === TripStatus.FINALIZED || trip.status === TripStatus.CONFIRMED) && (
                <button
                  onClick={() => setShowCancelModal(true)}
                  className="w-full py-4 border-2 border-rose-100 text-rose-600 rounded-2xl font-black uppercase tracking-[0.2em] hover:bg-rose-50 transition"
                >
                  Cancel Trip & Refund All
                </button>
              )}
              <button
                onClick={() => navigate(`/group-chat/${trip._id}`)}
                className="w-full py-5 bg-slate-100 text-slate-700 rounded-2xl font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3 hover:bg-slate-200 transition"
              >
                <MessageCircle className="w-6 h-6" />
                Go to Chat
              </button>
            </div>
          ) : status === 'accepted' ? (
            <div className="space-y-4">
              <button
                disabled
                className="w-full py-5 bg-emerald-500 text-white rounded-2xl font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3 shadow-lg shadow-emerald-100"
              >
                <UserCheck className="w-6 h-6" />
                Connected
              </button>
              <button
                onClick={() => navigate(`/group-chat/${trip._id}`)}
                className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3 shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition"
              >
                <MessageCircle className="w-6 h-6" />
                message
              </button>

              <p className="text-center text-slate-400 text-sm font-medium italic">
                You are already travel buddies for this trip!
              </p>
            </div>
          ) : status === 'pending' ? (
            <button
              disabled
              className="w-full py-5 bg-amber-50 text-amber-600 border-2 border-amber-200 rounded-2xl font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3"
            >
              <Clock className="w-6 h-6" />
              Request Sent
            </button>
          ) : status === 'rejected' ? (
            <div className="space-y-4">
              <button
                disabled
                className="w-full py-5 bg-rose-50 text-rose-600 border-2 border-rose-200 rounded-2xl font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3"
              >
                <X className="w-6 h-6" />
                Request Rejected
              </button>
              <p className="text-center text-slate-400 text-sm font-medium italic">
                Your request to join this trip was not accepted.
              </p>
            </div>
          ) : status === 'incoming_pending' ? (
            <button
              onClick={() => navigate('/connection-requests')}
              className="w-full py-5 bg-indigo-100 text-indigo-700 rounded-2xl font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3 hover:bg-indigo-200 transition shadow-lg shadow-indigo-50"
            >
              <UserPlus className="w-6 h-6" />
              View Incoming Request
            </button>
          ) : (
            <button
              onClick={handleSendRequest}
              disabled={status === 'loading'}
              className="w-full py-5 bg-blue-500 hover:bg-blue-600 text-white rounded-2xl font-black uppercase tracking-[0.2em] transition-all transform active:scale-95 shadow-xl shadow-blue-200 flex items-center justify-center gap-3 overflow-hidden"
            >
              {status === 'loading' ? (
                <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin"></div>
              ) : (
                'Send request'
              )}
            </button>
          )}
        </div>
      </div>

      {/* Cancel Trip Confirmation Modal */}
      {showCancelModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div
            className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm"
            onClick={() => setShowCancelModal(false)}
          />
          <div className="bg-white rounded-[2.5rem] p-8 w-full max-w-md relative animate-in fade-in zoom-in duration-300 shadow-2xl border border-slate-100">
            <div className="flex justify-between items-center mb-6">
              <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center text-rose-600">
                <AlertCircle size={24} />
              </div>
              <button
                onClick={() => setShowCancelModal(false)}
                className="p-2 hover:bg-slate-100 rounded-full transition-colors"
              >
                <X size={24} className="text-slate-400" />
              </button>
            </div>
            <h2 className="text-2xl font-black text-slate-900 mb-2">Cancel Trip?</h2>
            <p className="text-slate-500 text-sm mb-8 font-medium">
              Are you sure you want to cancel this trip? <br />
              <span className="text-rose-600 font-bold">
                All members will be refunded 100% of their deposits
              </span>{' '}
              to their TripBuddy Wallet. This action cannot be undone.
            </p>

            <div className="flex flex-col gap-3">
              <button
                onClick={handleCancelTrip}
                disabled={isCancelling}
                className="w-full py-5 bg-rose-600 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-rose-700 transition shadow-xl shadow-rose-100 disabled:opacity-50 flex items-center justify-center gap-3"
              >
                {isCancelling ? <Loader2 className="animate-spin" /> : <>Yes, Cancel Trip</>}
              </button>
              <button
                onClick={() => setShowCancelModal(false)}
                className="w-full py-4 bg-slate-50 text-slate-500 rounded-2xl font-black uppercase tracking-widest hover:bg-slate-100 transition"
              >
                No, Keep Trip
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default TripDetails;

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Calendar,
  MapPin,
  Users,
  Plus,
  Trash2,
  Save,
  ArrowLeft,
  Settings,
  Clock,
  Sparkles,
  ChevronRight,
  Loader2,
  CheckCircle2,
  Wand2,
  UserSearch,
  Search,
  RotateCcw,
  Star,
  BadgeCheck,
  Send,
  XCircle,
} from 'lucide-react';
import { tripService } from '../../services/c.trip.service';
import { aiService } from '../../services/c.ai.service';
import { guideService } from '../../services/c.guide.service';
import { paymentService } from '../../services/c.payment.service';
import { TripStatus } from '../../constants/TripStatus';
import type { ITrip, IItineraryItem, IGuide, IGuideInvitation } from '../../interface/ITripdetails';
import type { IPayment } from '../../interface/IPayment';
import toast from 'react-hot-toast';
import api from '../../utils/api';

const TripManagementPage = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [trip, setTrip] = useState<ITrip | null>(null);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [isHovering, setIsHovering] = useState(false);
  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
  const [activeTab, setActiveTab] = useState<'itinerary' | 'members' | 'settings' | 'guide'>(
    'itinerary'
  );

  // Itinerary State
  const [itinerary, setItinerary] = useState<IItineraryItem[]>([]);

  // Guide Search State
  const [guides, setGuides] = useState<IGuide[]>([]);
  const [guideLoading, setGuideLoading] = useState(false);
  const [guideDestination, setGuideDestination] = useState('');
  const [guideMaxPrice, setGuideMaxPrice] = useState(5000);
  const [assigningGuideId, setAssigningGuideId] = useState<string | null>(null);
  const [invitations, setInvitations] = useState<IGuideInvitation[]>([]);
  const [payments, setPayments] = useState<IPayment[]>([]);

  const getGuideInvitationStatus = (guideId: string) => {
    return invitations.find(inv => {
      const gId = typeof inv.guideId === 'string' ? inv.guideId : inv.guideId?._id;
      return gId === guideId;
    });
  };

  useEffect(() => {
    const loadTrip = async () => {
      if (!id) return;
      try {
        const data = await tripService.getTripById(id);
        setTrip(data);

        // Initialize itinerary if it exists, or create default days based on trip duration
        if (data.itinerary && data.itinerary.length > 0) {
          setItinerary(data.itinerary);
        } else {
          const days = generateDefaultItinerary(data.startDate, data.endDate);
          setItinerary(days);
        }

        // Fetch invitations for this trip
        const invRes = await api.get<{ data: IGuideInvitation[] }>('/api/guide-invitations/outbound');
        setInvitations(invRes.data.data.filter((inv: IGuideInvitation) => {
          const tId = typeof inv.tripId === 'string' ? inv.tripId : inv.tripId?._id;
          return tId === id;
        }));

        // Fetch payments for this trip
        const paymentsData = await paymentService.getTripPayments(id);
        setPayments(paymentsData);
      } catch (error) {
        toast.error('Failed to load trip data');
        navigate('/profile');
      } finally {
        setLoading(false);
      }
    };
    loadTrip();
  }, [id, navigate]);

  const generateDefaultItinerary = (start: string | Date, end: string | Date): IItineraryItem[] => {
    const startDate = new Date(start);
    const endDate = new Date(end);
    const daysCount =
      Math.ceil((endDate.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24)) + 1;

    const itineraryItems: IItineraryItem[] = [];
    for (let i = 0; i < daysCount; i++) {
      const currentDate = new Date(startDate);
      currentDate.setDate(startDate.getDate() + i);
      itineraryItems.push({
        day: i + 1,
        date: currentDate,
        activities: [],
      });
    }
    return itineraryItems;
  };

  const handleAddActivity = (dayIndex: number) => {
    const NewItinerary = [...itinerary];
    NewItinerary[dayIndex].activities.push({
      time: '12:00',
      activity: '',
      location: '',
      notes: '',
    });
    setItinerary(NewItinerary);
  };

  const handleActivityChange = (
    dayIndex: number,
    activityIndex: number,
    field: keyof IItineraryItem['activities'][0],
    value: string
  ) => {
    const NewItinerary = [...itinerary];
    const activity = NewItinerary[dayIndex].activities[activityIndex];
    (activity as Record<string, string>)[field] = value;
    setItinerary(NewItinerary);
  };

  const handleRemoveActivity = (dayIndex: number, activityIndex: number) => {
    const NewItinerary = [...itinerary];
    NewItinerary[dayIndex].activities.splice(activityIndex, 1);
    setItinerary(NewItinerary);
  };

  const handleSaveItinerary = async () => {
    if (!id) return;
    try {
      setIsSaving(true);
      await tripService.updateTrip(id, { itinerary });
      toast.success('Itinerary saved successfully!');
      setIsSaved(true);
    } catch (error) {
      toast.error('Failed to save itinerary');
    } finally {
      setIsSaving(false);
    }
  };

  // Guide Search
  const fetchGuides = async (destination = guideDestination, maxPrice = guideMaxPrice) => {
    setGuideLoading(true);
    try {
      const res = await api.get('/api/guides/all', {
        params: { destination, maxPrice, page: 1, limit: 12 },
      });
      setGuides(res.data.data.guides);
    } catch {
      toast.error('Failed to fetch guides');
    } finally {
      setGuideLoading(false);
    }
  };

  const handleAssignGuide = async (guideId: string | null) => {
    if (!id) return;
    setAssigningGuideId(guideId);
    try {
      const updatedTrip = await tripService.assignGuide(id, guideId);
      setTrip(updatedTrip);
      toast.success(guideId ? 'Guide assigned to trip!' : 'Guide removed from trip.');
    } catch (err: unknown) {
      const errorObj = err as { response?: { data?: { message?: string } } };
      toast.error(errorObj?.response?.data?.message || 'Failed to update guide assignment');
    } finally {
      setAssigningGuideId(null);
    }
  };

  const handleInviteGuide = async (guideId: string) => {
    if (!id) return;
    setAssigningGuideId(guideId);
    try {
      await guideService.sendInvitation(id, guideId);
      toast.success('Trip request sent to guide!');

      // Refresh invitations
      const invRes = await api.get<{ data: IGuideInvitation[] }>('/api/guide-invitations/outbound');
      setInvitations(invRes.data.data.filter((inv: IGuideInvitation) => {
        const tId = typeof inv.tripId === 'string' ? inv.tripId : inv.tripId?._id;
        return tId === id;
      }));
    } catch (err: unknown) {
      const errorObj = err as { response?: { data?: { message?: string } } };
      toast.error(errorObj?.response?.data?.message || 'Failed to send invitation');
    } finally {
      setAssigningGuideId(null);
    }
  };

  const handleCancelTrip = async () => {
    if (
      !id ||
      !window.confirm(
        'Are you sure you want to cancel this trip? This will refund all members 100% and cannot be undone.'
      )
    )
      return;
    try {
      setIsSaving(true);
      await tripService.cancelTrip(id);
      toast.success('Trip cancelled and members refunded.');
      navigate('/profile');
    } catch (error) {
      toast.error('Failed to cancel trip');
    } finally {
      setIsSaving(false);
    }
  };

  const handleMarkCompleted = async () => {
    if (!id) return;
    try {
      setIsSaving(true);
      await tripService.updateTrip(id, { status: TripStatus.COMPLETED });
      toast.success('Trip marked as completed!');
      setTrip(prev => (prev ? { ...prev, status: TripStatus.COMPLETED } : null));
    } catch (error) {
      toast.error('Failed to update status');
    } finally {
      setIsSaving(false);
    }
  };

  const handleAIGenerateItinerary = async () => {
    if (!trip) return;

    try {
      setIsGeneratingAI(true);
      const prompt = `Act as an expert travel planner. Generate a detailed, day-by-day itinerary for a trip to ${trip.destination} from ${new Date(trip.startDate).toLocaleDateString()} to ${new Date(trip.endDate).toLocaleDateString()}.

The travelers are interested in: ${trip.preferences?.interests?.join(', ') || 'general sightseeing'}.
They prefer ${trip.preferences?.transport || 'any'} transport and ${trip.preferences?.accommodation || 'any'} accommodation.

Return ONLY a valid JSON array of objects representing the days. Each object must follow this exact structure:
[
  {
    "day": 1,
    "activities": [
      {
        "time": "09:00",
        "activity": "Detailed activity description",
        "location": "Specific location or venue name",
        "notes": "Any helpful tips or context"
      }
    ]
  }
]
Do not include any other text, markdown formatting, or code blocks outside the JSON array. Return raw JSON.`;

      const responseText = await aiService.getChatResponse(prompt);

      let jsonString = responseText;
      if (jsonString.startsWith('\`\`\`json')) {
        jsonString = jsonString.replace(/\`\`\`json\n/g, '').replace(/\n\`\`\`/g, '');
      } else if (jsonString.startsWith('\`\`\`')) {
        jsonString = jsonString.replace(/\`\`\`\n/g, '').replace(/\n\`\`\`/g, '');
      }

      const generatedData = JSON.parse(jsonString);

      interface AIGeneratedDay {
        activities?: {
          time?: string;
          activity?: string;
          location?: string;
          notes?: string;
        }[];
      }

      const newItinerary: IItineraryItem[] = generatedData.map((dayData: AIGeneratedDay, index: number) => {
        const currentDate = new Date(trip.startDate);
        currentDate.setDate(currentDate.getDate() + index);

        return {
          day: index + 1,
          date: currentDate,
          activities: (dayData.activities || []).map((act) => ({
            time: act.time || '10:00',
            activity: act.activity || 'Activity',
            location: act.location || '',
            notes: act.notes || '',
          })),
        };
      });

      setItinerary(newItinerary);
      toast.success('AI generated a brilliant itinerary!');
    } catch (error) {
      console.error(error);
      toast.error('Failed to generate itinerary. Please try again.');
    } finally {
      setIsGeneratingAI(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
      </div>
    );
  }

  if (!trip) return null;

  return (
    <div className="min-h-screen bg-[#F8FAFC]">
      {/* Dynamic Header */}
      <div className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 py-4 shadow-sm backdrop-blur-md bg-white/80">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button
              onClick={() => navigate(-1)}
              className="p-2.5 hover:bg-slate-50 rounded-2xl text-slate-400 hover:text-indigo-600 transition-all border border-transparent hover:border-slate-100"
            >
              <ArrowLeft size={20} />
            </button>
            <div>
              <h1 className="text-2xl font-black text-slate-900 tracking-tighter uppercase">
                {trip.title}
              </h1>
              <div className="flex items-center gap-2 mt-0.5">
                <span className="bg-indigo-50 text-indigo-600 text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded-md border border-indigo-100/50">
                  Owner Access
                </span>
                <span className="text-slate-300">/</span>
                <span className="text-slate-500 text-xs font-bold flex items-center gap-1">
                  <MapPin size={12} /> {trip.destination}
                </span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button
              onClick={handleSaveItinerary}
              onMouseEnter={() => setIsHovering(true)}
              onMouseLeave={() => setIsHovering(false)}
              disabled={isSaving}
              className={`px-6 py-3 rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-lg transition-all flex items-center gap-2 ${
                isSaved && !isHovering
                  ? 'bg-emerald-500 text-white shadow-emerald-100 cursor-default'
                  : 'bg-indigo-600 text-white shadow-indigo-100 hover:bg-slate-900 active:scale-95'
              }`}
            >
              {isSaving ? (
                <Loader2 size={14} className="animate-spin" />
              ) : isSaved && !isHovering ? (
                <CheckCircle2 size={14} className="animate-in zoom-in duration-300" />
              ) : (
                <Save size={14} />
              )}
              {isSaving ? 'Saving...' : isSaved && !isHovering ? 'Saved!' : 'Save Plan'}
            </button>
          </div>
        </div>
      </div>

      {/* Expiry Warning */}
      {trip &&
        new Date(new Date(trip.startDate).getTime() + 3 * 24 * 60 * 60 * 1000) < new Date() &&
        trip.status !== TripStatus.CONFIRMED &&
        trip.status !== TripStatus.COMPLETED && (
          <div className="bg-rose-50 border-b border-rose-100 px-6 py-3">
            <div className="max-w-6xl mx-auto flex items-center justify-between">
              <div className="flex items-center gap-3 text-rose-600">
                <Clock size={16} className="animate-pulse" />
                <span className="text-[11px] font-black uppercase tracking-widest">
                  This trip has expired! The scheduled dates have passed.
                </span>
              </div>
              <p className="text-[10px] text-rose-500 font-bold italic">
                Update the dates in "Management" to renew/reschedule.
              </p>
            </div>
          </div>
        )}

      <main className="max-w-6xl mx-auto px-6 py-10">
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
          {/* Sidebar Tabs */}
          <div className="lg:col-span-1 space-y-2">
            {[
              { id: 'itinerary', label: 'Itinerary Builder', icon: Calendar },
              { id: 'members', label: 'Trip Members', icon: Users },
              { id: 'guide', label: 'Find Guide', icon: UserSearch },
              { id: 'settings', label: 'Management', icon: Settings },
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as 'itinerary' | 'members' | 'settings' | 'guide')}
                className={`w-full flex items-center justify-between p-4 rounded-3xl transition-all border-2 ${
                  activeTab === tab.id
                    ? 'bg-white border-indigo-600 shadow-xl shadow-indigo-100/20 text-indigo-700'
                    : 'bg-transparent border-transparent text-slate-400 hover:bg-white hover:border-slate-100'
                } group`}
              >
                <div className="flex items-center gap-4">
                  <div
                    className={`p-2.5 rounded-2xl transition-all ${activeTab === tab.id ? 'bg-indigo-50' : 'bg-slate-50 group-hover:bg-indigo-50'}`}
                  >
                    <tab.icon
                      size={20}
                      className={
                        activeTab === tab.id
                          ? 'text-indigo-600'
                          : 'text-slate-400 group-hover:text-indigo-600'
                      }
                    />
                  </div>
                  <span className="font-black uppercase tracking-widest text-[11px]">
                    {tab.label}
                  </span>
                </div>
                <ChevronRight
                  size={16}
                  className={`transition-transform duration-300 ${activeTab === tab.id ? 'translate-x-1' : 'opacity-0'}`}
                />
              </button>
            ))}

            <div className="mt-12 bg-white/50 border border-slate-100 rounded-[2.5rem] p-6 backdrop-blur-sm">
              <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 mb-4 px-2">
                Quick Summary
              </h4>
              <div className="space-y-4">
                <div className="flex justify-between items-center p-3 rounded-2xl bg-white border border-slate-50">
                  <span className="text-xs font-bold text-slate-500">Total Budget</span>
                  <span className="text-sm font-black text-slate-900">
                    ₹{trip.budget?.toLocaleString()}
                  </span>
                </div>
                <div className="flex justify-between items-center p-3 rounded-2xl bg-white border border-slate-50">
                  <span className="text-xs font-bold text-slate-500">Status</span>
                  <span className="text-[10px] font-black uppercase tracking-widest bg-emerald-50 text-emerald-600 px-2 py-0.5 rounded-md">
                    {trip.status}
                  </span>
                </div>
              </div>
            </div>
          </div>

          {/* Main Content Area */}
          <div className="lg:col-span-3">
            {activeTab === 'itinerary' && (
              <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-500">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-indigo-50/50 p-6 rounded-[2.5rem] border border-indigo-100/50 shadow-sm relative overflow-hidden group">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-purple-500/10 rounded-full blur-3xl -mr-10 -mt-10 pointer-events-none transition-all group-hover:bg-purple-500/20"></div>
                  <div className="absolute bottom-0 left-0 w-32 h-32 bg-indigo-500/10 rounded-full blur-3xl -ml-10 -mb-10 pointer-events-none transition-all group-hover:bg-indigo-500/20"></div>

                  <div className="relative z-10 flex items-center gap-4">
                    <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center shadow-md border border-indigo-100 flex-shrink-0 text-indigo-600">
                      <Wand2 size={24} />
                    </div>
                    <div>
                      <h3 className="text-lg font-black text-indigo-950 tracking-tight">
                        AI Itinerary Generator
                      </h3>
                      <p className="text-[11px] text-indigo-600/70 font-bold uppercase tracking-widest mt-1">
                        Let Trip Buddy automatically plan your trip
                      </p>
                    </div>
                  </div>
                  <button
                    onClick={handleAIGenerateItinerary}
                    disabled={isGeneratingAI || isSaving}
                    className="relative z-10 flex w-full md:w-auto items-center justify-center gap-2 px-6 py-3.5 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-lg shadow-indigo-200/50 hover:shadow-xl hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:hover:scale-100 disabled:cursor-not-allowed"
                  >
                    {isGeneratingAI ? (
                      <Loader2 size={16} className="animate-spin" />
                    ) : (
                      <Wand2 size={16} />
                    )}
                    {isGeneratingAI ? 'Generating Magic...' : 'Auto-Generate Plan'}
                  </button>
                </div>
                {itinerary.map((day, dayIdx) => (
                  <div
                    key={dayIdx}
                    className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden group hover:shadow-xl transition-all duration-500"
                  >
                    <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/30">
                      <div className="flex items-center gap-6">
                        <div className="w-16 h-16 bg-white rounded-3xl flex flex-col items-center justify-center shadow-lg border border-slate-100 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500">
                          <span className="text-[10px] font-black uppercase tracking-widest leading-none">
                            Day
                          </span>
                          <span className="text-2xl font-black leading-none mt-1">{day.day}</span>
                        </div>
                        <div>
                          <h3 className="text-xl font-black text-slate-900 tracking-tighter">
                            {new Date(day.date).toLocaleDateString(undefined, {
                              weekday: 'long',
                              month: 'long',
                              day: 'numeric',
                            })}
                          </h3>
                          <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">
                            Plan your activities for today
                          </p>
                        </div>
                      </div>
                      <button
                        onClick={() => handleAddActivity(dayIdx)}
                        className="flex items-center gap-2 px-5 py-2.5 bg-white border-2 border-slate-100 hover:border-indigo-600 hover:text-indigo-600 rounded-2xl font-black uppercase tracking-widest text-[10px] transition-all shadow-sm"
                      >
                        <Plus size={14} /> Add Event
                      </button>
                    </div>

                    <div className="p-8 space-y-4">
                      {day.activities.length === 0 ? (
                        <div className="py-12 flex flex-col items-center justify-center border-2 border-dashed border-slate-100 rounded-3xl bg-slate-50/20">
                          <Sparkles className="text-slate-200 w-12 h-12 mb-4" />
                          <p className="text-slate-400 text-sm font-bold uppercase tracking-widest italic">
                            No activities planned yet
                          </p>
                        </div>
                      ) : (
                        day.activities.map((activity, actIdx) => (
                          <div
                            key={actIdx}
                            className="bg-slate-50/50 p-6 rounded-3xl border border-slate-100 flex flex-col md:flex-row gap-6 relative group/act hover:bg-white hover:shadow-lg transition-all"
                          >
                            <div className="w-full md:w-32">
                              <div className="relative">
                                <Clock
                                  className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-400"
                                  size={16}
                                />
                                <input
                                  type="time"
                                  value={activity.time}
                                  onChange={e =>
                                    handleActivityChange(dayIdx, actIdx, 'time', e.target.value)
